INSERT INTO public.photos VALUES (24348, 'Foro de Caesaraugusta a‚îú‚ñío 150', 'El Foro de Caesaraugusta ten‚îú¬°a una superficie de casi 24.000 metros cuadrados, extendi‚îú¬Ændose por la plaza de la Seo, el palacio arzobispal, la Casa de la Iglesia, la Seo, la plaza de San Bruno, las calles de San Valero, Cu‚îú¬Ællar y del Cisne, y gran parte de la calle de Pabostr‚îú¬°a. Era el centro pol‚îú¬°tico, administrativo, religioso y econ‚îú‚îÇmico de la colonia. El templo estar‚îú¬°a dentro de lo que hoy es la Seo, la curia en un edificio ubicado en el sureste del complejo, la bas‚îú¬°lica en la Casa de la Iglesia y el palacio arzobispal. A ello habr‚îú¬°a que a‚îú‚ñíadir locales comerciales, el archivo de la ciudad, la ceca donde se acu‚îú‚ñíaba moneda, oficinas, un espacio destinado al culto imperial (a‚îú‚ïën no descubierto) y conjuntos escult‚îú‚îÇricos como una estatua ecuestre de Tiberio, en la plaza, a cielo abierto. En la imagen, representaci‚îú‚îÇn idealizada de la plaza del Foro, con el templo principal en primer t‚îú¬Ærmino.', NULL, NULL, NULL, NULL, 'CASCO HIST‚îú√¥RICO', 41.65469300, -0.87571400, '0101000020E61000006DC7D45DD905ECBFC7F5EFFACCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14754482467.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14754482467.webp', 'https://www.flickr.com/photos/zaragozaantigua/14754482467/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24589, 'La Lonja y la puerta del ‚îú√ºngel 1862', '"Imagen de la desaparecida Puerta del ‚îú√ºngel, que fue erigida por el arquitecto Miguel Jeliner y Germ‚îú√≠ con motivo de la visita de Isabel II a la ciudad, en 1860. Esta puerta pretend‚îú¬°a recordar la antigua puerta medieval de la ciudad, que hab‚îú¬°a sido destruida durante los Sitios (1808-1809). El grupo escult‚îú‚îÇrico del ‚îú√ºngel Custodio, que cobija bajo sus alas una alegor‚îú¬°a del r‚îú¬°o Ebro y un le‚îú‚îÇn, parece claramente un fotomontaje realizado por J‚îú‚ïëdez a partir de una fotograf‚îú¬°a del dibujo del proyecto." Jos‚îú¬Æ Antonio Hern‚îú√≠ndez Latas. Fuente: Mariano J‚îú‚ïëdez y Ortiz. Colecci‚îú‚îÇn Boisset-Ib‚îú√≠‚îú‚ñíez. Libro Primeros tiempos de la fotograf‚îú¬°a en Zaragoza.', 1862, 1862, 1862, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65596400, -0.87601300, '0101000020E6100000FDDD3B6A4C08ECBF3AADDBA0F6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14893920231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14893920231.webp', 'https://www.flickr.com/photos/zaragozaantigua/14893920231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24606, 'Arco Palacio Arzobispal a‚îú‚ñíos 20', 'AHPZ . Archivo Coyne. Arco que une la fachada de la capilla de San Miguel (parroquieta) de la Catedral de San Salvador (La Seo), con el palacio arzobispal. Llamado el "Arco del Arzobispo", fue derribado el 2 de julio de 1969. Hemos volteado en horizontal la imagen, que estaba al rev‚îú¬Æs.', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65516600, -0.87557400, '0101000020E6100000FD4AE7C3B304ECBFBFB9BF7ADCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14750877890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14750877890.webp', 'https://www.flickr.com/photos/zaragozaantigua/14750877890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24610, 'Arco del De‚îú√≠n 1950', 'Arco del De‚îú√≠n o paso volado sobre la antigua calle de la Pabostr‚îú¬°a con el que se pod‚îú¬°a acceder directamente desde la Casa del De‚îú√≠n de la Seo a la iglesia hom‚îú‚îÇnima, en una imagen antes de ser sometido al proceso de restauraci‚îú‚îÇn que a‚îú‚ñíos despu‚îú¬Æs le dar‚îú¬°a su actual aspecto. Fuente visual: AHPZ-Archivo Coyne, Manuel Coyne', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65421200, -0.87507000, '0101000020E610000038BEF6CC9200ECBF4C530438BDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14913145355.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14913145355.webp', 'https://www.flickr.com/photos/zaragozaantigua/14913145355/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24611, 'Roscones 1940', '29 de enero de 1940. Venta del Rosc‚îú‚îÇn de San Valero en la puerta de la catedral de La Seo.', 1940, 1940, 1940, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65513200, -0.87584800, '0101000020E6100000548B8862F206ECBF1348895DDBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14985777801.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14985777801.webp', 'https://www.flickr.com/photos/zaragozaantigua/14985777801/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24614, 'Muro Parroquieta 1920', 'Juan Cabr‚îú¬Æ Aguil‚îú‚îÇ. Archivo Cabr‚îú¬Æ. 1920. "Fachada lateral de la Catedral de La Seo del Salvador conocido como muro de la Parroquieta (Zaragoza)."', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65506200, -0.87551500, '0101000020E6100000C00985083804ECBF1A6D5512D9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15069672475.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15069672475.webp', 'https://www.flickr.com/photos/zaragozaantigua/15069672475/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24615, 'Arco del De‚îú√≠n 1975', 'Archivo Municipal de Zaragoza. Gerardo Sancho Ramo. 23/01/1975. El restaurado Arco del De‚îú√≠n recuperando la funci‚îú‚îÇn para la que fue construido: g‚îú‚îÇtico garaje cubierto para veh‚îú¬°culos a motor de explosi‚îú‚îÇn. Como escribi‚îú‚îÇ Blasco Ijazo, "La casa da verdadero empaque a ese bello rinc‚îú‚îÇn zaragozano, que mantiene toda la esencia de su tipismo en aquel contorno de la vieja ciudad." Am‚îú¬Æn. La imagen est‚îú√≠ tomada desde la calle de Palafox, en direcci‚îú‚îÇn a la calle del De‚îú√≠n.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65418300, -0.87512700, '0101000020E610000048179B560A01ECBFB24CBF44BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15143864778.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15143864778.webp', 'https://www.flickr.com/photos/zaragozaantigua/15143864778/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24617, 'Arco del De‚îú√≠n a‚îú‚ñíos 20', 'Miguel Faci Abad. 1920-25. "Zaragoza. Arco del De‚îú√≠n." Esta es una foto del Arco del De‚îú√≠n, pero que aunque no sale m‚îú√≠s que un pedacito, es muy interesante. A nivel de suelo, desde debajo del Arco del De‚îú√≠n, una mirada hacia la calle del De‚îú√≠n, con visual a otro pasadizo voladizo, este funcional y sin pretensiones est‚îú¬Æticas, que tambi‚îú¬Æn conectaba el complejo catedralicio con la casona de la izquierda. Ambos elementos est‚îú√≠n hoy volados. Al fondo, las traseras de "Casa Armijo", que en tiempos tambi‚îú¬Æn formara parte del emporio eclesi‚îú√≠stico de la Seo, como vivienda de su Arcipreste, y que ahora era propiedad de una notable familia de la ciudad, de ese apellido. Fuente visual: "Miguel y Gabriel Faci. Fot‚îú‚îÇgrafos fundadores de la Real Sociedad Fotogr‚îú√≠fica de Zaragoza.", Alfredo Romero y Ricardo Centellas, Diputaci‚îú‚îÇn Provincial de Zaragoza, 1999.', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65418300, -0.87512700, '0101000020E610000048179B560A01ECBFB24CBF44BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15343174768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15343174768.webp', 'https://www.flickr.com/photos/zaragozaantigua/15343174768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24620, 'Felipe V 1701', '"Le Serment prest‚îú¬Æe par le Roy d''Espagne a Saragoce Royaume d''Aragon le 17 Septembre 1701". Ilustraci‚îú‚îÇn que recrea idealmente el juramento de los Fueros de Arag‚îú‚îÇn por parte del rey Felipe en 1701 en la La Catedral del Salvador en su Epifan‚îú¬°a de Zaragoza (La Seo). Esta imagen forma parte, en su parte inferior, de la estampa titulada "La benediction nuptiale donee solennellement AV / Roy et a la Reine D''Espagne a Feguieres le 5e. novembre 1701" (Boda del Rey Felipe de Borb‚îú‚îÇn con la Reina Mar‚îú¬°a Luisa Gabriela de Saboya en la localidad catalana de Figueras. ‚îú√´l ten‚îú¬°a 17 a‚îú‚ñíos de edad. Ella, 13). Fuente visual: gallica.bnf.fr/', 1701, 1701, 1701, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15555463059.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15555463059.webp', 'https://www.flickr.com/photos/zaragozaantigua/15555463059/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24621, 'Palmeros del De‚îú√≠n 1942', 'Archivo Municipal. Gerardo Sancho Ramo. 1942. Imagen de una procesi‚îú‚îÇn de palmas (plantas muy comunes en la zona) portadas por autoridades eclesi‚îú√≠sticas varias en la calle del De‚îú√≠n, y acompa‚îú‚ñíadas por el personal del ayuntamiento que para trabajar se pone pelucas de ‚îú¬Æpoca. Las se‚îú‚ñíoras, de negro y cubiertas, participan, pero muy en segundo plano. La procesionaria viene de la calle de la Pabostr‚îú¬°a, y est‚îú√≠ a punto de llegar al antiguo arco del De‚îú√≠n, despu‚îú¬Æs de pasar por debajo del pasaje arquitrabado de la calle De‚îú√≠n que conectaba dependencias de la Seo. Esta conjunci‚îú‚îÇn entre la instituci‚îú‚îÇn municipal y una determinada confesi‚îú‚îÇn religiosa, perdura. El pasaje arquitrabado, y el edificio de la izquierda, no.', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15595905729.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15595905729.webp', 'https://www.flickr.com/photos/zaragozaantigua/15595905729/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24623, 'Calle de Don Juan de Arag‚îú‚îÇn 1949', 'Imagen de la calle Don Juan de Arag‚îú‚îÇn, capturada desde su comienzo en la cercana plaza de Santa Marta. El edificio que recibe plena insolaci‚îú‚îÇn es el antiguo palacio de Armijo. Los edificios de la inmediata acera derecha ser‚îú√≠n piqueteados, retranqueados, y sustituidos luego por otros m‚îú√≠s modernos, como sede de la municipal Casa de la Mujer. Fuente visual: Archivo Mora, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65394000, -0.87602000, '0101000020E61000009C8A54185B08ECBFEBC5504EB4D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15752862165.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15752862165.webp', 'https://www.flickr.com/photos/zaragozaantigua/15752862165/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24628, 'Calle del De‚îú√≠n 1949', 'Imagen de la calle del De‚îú√≠n, con el Arco del mismo nombre al fondo, soleado y en curva, antes de ser "restaurado". En primer t‚îú¬Ærmino, el arquitrabado pseudo-arco que exist‚îú¬°a en esa calle, una antigua y pr‚îú√≠ctica costumbre de conseguir un espacio habitacional extra, sin tener que modificar el planeamiento existente, ni preocuparse por la cimentaci‚îú‚îÇn de la obra. Tiempo despu‚îú¬Æs, este "arco" y la vivienda de la que se extend‚îú¬°a, ser‚îú¬°an derribados. Fuente visual: Juan Mora Insa, AMZ.', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65430700, -0.87501700, '0101000020E61000008335CEA62300ECBF9E45EF54C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21810308270.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21810308270.webp', 'https://www.flickr.com/photos/zaragozaantigua/21810308270/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24629, 'Foro de Caesaraugusta a‚îú‚ñío 150', 'Plano de situaci‚îú‚îÇn del Foro Romano de Caesaraugusta, sobre una representaci‚îú‚îÇn de Zaragoza actual. Museo del Puerto Fluvial, Ayuntamiento de Zaragoza. El Foro de Caesaraugusta ten‚îú¬°a una superficie de casi 24.000 metros cuadrados, extendi‚îú¬Ændose por la plaza de la Seo, el palacio arzobispal, la Casa de la Iglesia, la Seo, la plaza de San Bruno, las calles de San Valero, Cu‚îú¬Ællar y del Cisne, y gran parte de la calle de Pabostr‚îú¬°a. Era el centro pol‚îú¬°tico, administrativo, religioso y econ‚îú‚îÇmico de la colonia. El templo estar‚îú¬°a dentro de lo que hoy es la Seo, la curia en un edificio ubicado en el sureste del complejo, la bas‚îú¬°lica en la Casa de la Iglesia y el palacio arzobispal. A ello habr‚îú¬°a que a‚îú‚ñíadir locales comerciales, el archivo de la ciudad, la ceca donde se acu‚îú‚ñíaba moneda, oficinas, un espacio destinado al culto imperial (a‚îú‚ïën no descubierto) y conjuntos escult‚îú‚îÇricos como una estatua ecuestre de Tiberio, en la plaza, a cielo abierto. Fuente visual: eszaragoza.blogspot.com.es/2015/10/situacion-del-foro-rom...', NULL, NULL, NULL, NULL, 'CASCO HIST‚îú√¥RICO', 41.65482800, -0.87568800, '0101000020E61000001EFD2FD7A205ECBFA7406667D1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21897903483.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21897903483.webp', 'https://www.flickr.com/photos/zaragozaantigua/21897903483/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24630, 'Calle Pabostr‚îú¬°a 1971', 'Rinc‚îú‚îÇn de la calle Pabostr‚îú¬°a frente a la calle de Lucero ,donde se encontraba la panader‚îú¬°a y pasteler‚îú¬°a de la catedral. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65427500, -0.87564500, '0101000020E61000004CFDBCA94805ECBF92CB7F48BFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22526665104.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22526665104.webp', 'https://www.flickr.com/photos/zaragozaantigua/22526665104/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24632, 'Calle Lucero 1971', 'Vista de la esquina de la calle Lucero con la de la Pabostr‚îú¬°a. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1971, 1971, 1971, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65416300, -0.87568800, '0101000020E61000001EFD2FD7A205ECBF6AA0F99CBBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22731457247.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22731457247.webp', 'https://www.flickr.com/photos/zaragozaantigua/22731457247/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24633, 'Calle De‚îú√≠n 1972', 'Entorno de la Seo, en la calle del De‚îú√≠n. Al fondo, el arco del De‚îú√≠n. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65431500, -0.87516200, '0101000020E6100000647616BD5301ECBF20240B98C0D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22732389768.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22732389768.webp', 'https://www.flickr.com/photos/zaragozaantigua/22732389768/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24635, 'Calle Pabostr‚îú¬°a 1972', 'Calle Pabostr‚îú¬°a en su confluencia con la de Lucero (a la izquierda). Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65415500, -0.87559200, '0101000020E610000097749483D904ECBFE8C1DD59BBD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22830117020.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22830117020.webp', 'https://www.flickr.com/photos/zaragozaantigua/22830117020/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24639, 'Calle De‚îú√≠n 1974', 'Entorno de la Seo, en la calle del De‚îú√≠n. Al fondo, la calle Pabostr‚îú¬°a. En la pared de la derecha, rastros de las vigas de madera que soportaban el arquitrabado y a‚îú¬Æreo paso entre dependencias del Cabildo, derribado junto con las casas de la izquierda, con las que comunicaba. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1974, 1974, 1974, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65418700, -0.87527000, '0101000020E6100000FC6F253B3602ECBFF33B4D66BCD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23162406701.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23162406701.webp', 'https://www.flickr.com/photos/zaragozaantigua/23162406701/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24643, 'Plaza de La Seo c.1920', 'Vista de la plaza de La Seo desde la calle del Pilar. A la izquierda, paredes de la Lonja. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65542900, -0.87598800, '0101000020E6100000C40776FC1708ECBFCCECF318E5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24537098649.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24537098649.webp', 'https://www.flickr.com/photos/zaragozaantigua/24537098649/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24644, 'La Seo c.1920', 'Puerta principal de la Seo, ante la que se encuentran dos coches aparcados en doble fila. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65518900, -0.87592400, '0101000020E61000001502B9C49107ECBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24537190279.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24537190279.webp', 'https://www.flickr.com/photos/zaragozaantigua/24537190279/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24650, 'Calle Sepulcro c.1975', 'Desde la calle del Sepulcro, muros y restos de edificaciones derruidas en este entorno, a izquierda y derecha, desde mediados los a‚îú‚ñíos sesenta. Al fondo y tras el cubo de la Sacrist‚îú¬°a Mayor de la Seo, los vol‚îú‚ïëmenes de los ‚îú√≠bsides, el cimborrio y la torre campanario. A la derecha, el palacio Arzobispal. A‚îú‚ñíos m‚îú√≠s tarde, esta zona ser‚îú√≠ muy modificada con la ampliaci‚îú‚îÇn de la plaza de San Bruno y la construcci‚îú‚îÇn de pisos de promoci‚îú‚îÇn municipal.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65490600, -0.87498100, '0101000020E610000050E27327D8FFEBBF22FAB5F5D3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/29774366873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/29774366873.webp', 'https://www.flickr.com/photos/zaragozaantigua/29774366873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24651, 'Hu‚îú¬Ærfanos austr‚îú¬°acos 1948', 'El ejercicio de la caridad cristiana en la larga y penosa postguerra espa‚îú‚ñíola, y bajo un contexto internacional de "guerra fr‚îú¬°a", tuvo un notable episodio en la oficial campa‚îú‚ñía que, entre 1948 y 1950, tuvo como objeto a "los fugitivos de los pa‚îú¬°ses dominados por el comunismo bolchevique", y que tom‚îú‚îÇ cuerpo en la recepci‚îú‚îÇn de hu‚îú¬Ærfanos austr‚îú¬°acos primero, y tambi‚îú¬Æn polacos, que fueron acogidos en calidad de "cristianos perseguidos" en la denominada "Reserva espiritual de Occidente". Sobre el origen de estos ni‚îú‚ñíos, las cr‚îú‚îÇnicas oficiales dec‚îú¬°an en un primer momento que eran todos hu‚îú¬Ærfanos de guerra, que hab‚îú¬°an nacido en campos de concentraci‚îú‚îÇn y que ven‚îú¬°an desde Alemania e Italia, pero seg‚îú‚ïën la documentaci‚îú‚îÇn del International Tracing Service (Servicio Internacional de B‚îú‚ïësquedas, archivo de la persecuci‚îú‚îÇn de minor‚îú¬°as y opositores pol‚îú¬°ticos de todo tipo, la explotaci‚îú‚îÇn extrema del trabajo forzoso y el vasto desarraigo de las personas durante el gobierno del r‚îú¬Ægimen nacionalsocialista en Alemania), parece ser que en realidad proced‚îú¬°an de los Lebensborn, o centros de experimento eugen‚îú¬Æsico para engendrar al superhombre y extender la raza aria por el orbe, bien de la uni‚îú‚îÇn obligada de mujeres seleccionadas y soldados alemanes, o bien eran arrancados de sus familias por contener los rasgos exigidos para su posterior moldeado racial. Tambi‚îú¬Æn hab‚îú¬°a muchos con perfil ario reclutados de hijos de esclavos de la industria alemana. De esta forma, las j‚îú‚îÇvenes de Acci‚îú‚îÇn Cat‚îú‚îÇlica, y el Secretariado Nacional de Caridad gestionaron, junto con el Secretariado Diocesano local, el hospedaje y adopci‚îú‚îÇn temporal de estos ni‚îú‚ñíos centroeuropeos de planta aria que llegaron a la imperial y mariana Zaragoza. En la imagen, uno de los contingentes de peques austr‚îú¬°acos llegados a la ciudad. La gran mayor‚îú¬°a de estos ni‚îú‚ñíos fueron regresados luego con sus padres o familiares cercanos tras ser reclamados, pero otros (hu‚îú¬Ærfanos, o de padres desaparecidos) siguieron hasta que en 1956 se hicieron cargo de', 1948, 1948, 1948, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65581700, -0.87567500, '0101000020E6100000F697DD938705ECBF9694BBCFF1D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30244718036.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30244718036.webp', 'https://www.flickr.com/photos/zaragozaantigua/30244718036/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24653, 'Arco del De‚îú√≠n 1943', 'Acuarela de Ambrosio Ruste, 1943. Vista del arco del De‚îú√≠n desde la calle de Palafox. Fuente: www.facebook.com/photo.php?fbid=10207055451304534&set...', 1943, 1943, 1943, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65446500, -0.87503500, '0101000020E61000001C5F7B664900ECBF36B05582C5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33562594714.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33562594714.webp', 'https://www.flickr.com/photos/zaragozaantigua/33562594714/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24655, 'Cimborrio de la Seo 1948', '"Cimborrio de la Seo, templo en que se coronaron las Reinas de Arag‚îú‚îÇn". Dibujo de los hermanos Albareda, 1948. Fuente: "Coronaci‚îú‚îÇn de las Reinas de Arag‚îú‚îÇn", La Cadiera, 1948.', 1948, 1948, 1948, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65497600, -0.87540700, '0101000020E61000002810768A5503ECBF1BD5E940D6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40736151224.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40736151224.webp', 'https://www.flickr.com/photos/zaragozaantigua/40736151224/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24659, 'Calle del De‚îú√≠n c.1912', 'Imagen capturada en el principio de la calle de Jos‚îú¬Æ Palafox y centrada en el ‚îú‚ïëltimo tramo de la enrevesada calle del De‚îú√≠n, donde destaca el hom‚îú‚îÇnimo arco medieval que conectaba los inmuebles de los n‚îú‚ïëmeros 10 y 5 de esa calle, ‚îú¬Æste ‚îú‚ïëltimo adosado a la catedral de la Seo e inmediato a su ingreso por la Puerta de San Bartolom‚îú¬Æ.', 1912, 1912, 1912, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65439600, -0.87494700, '0101000020E61000004B77D7D990FFEBBF0D51853FC3D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49970539642.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49970539642.webp', 'https://www.flickr.com/photos/zaragozaantigua/49970539642/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24660, 'Plaza de La Seo 1919', 'Aspecto de la puerta de acceso a la catedral de San Salvador o la Seo, en la plaza hom‚îú‚îÇnima, durante la ceremonia de entierro de Francisco Javier Azlor de Arag‚îú‚îÇn e Idi‚îú√≠quez (Toulouse, 1842, Madrid, 1919), VI duque de Granada de Ega. Este arist‚îú‚îÇcrata fue senador del Reino desde 1877, caballero de la orden de San Juan de Malta y de la Real Maestranza de Caballer‚îú¬°a de Zaragoza. Sus restos fueron trasladados en tren desde la estaci‚îú‚îÇn de Atocha de Madrid.', 1919, 1919, 1919, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65509100, -0.87599000, '0101000020E6100000F2EF332E1C08ECBFB4739A05DAD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52024040284.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52024040284.webp', 'https://www.flickr.com/photos/zaragozaantigua/52024040284/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24867, 'Puente de Piedra 1991', 'Imagen capturada desde cierta altura en la Casa de la Iglesia con una vista parcial del puente de Piedra tras la importante restauraci‚îú‚îÇn del mismo inaugurada el 8 de mayo de 1991 y que le dot‚îú‚îÇ de su actual aspecto. En primer t‚îú¬Ærmino, uno de los cuatro Leones cincelados por Francisco Rallo y fundidos en bronce que flanquean los accesos al puente. Transita hacia la terminal de Zaragoza un autob‚îú‚ïës que conecta con los municipios de Movera y Pastriz, en la margen izquierda.', 1991, 1991, 1991, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65632000, -0.87594500, '0101000020E6100000F20703CFBD07ECBFF9DA334B02D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50441583651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50441583651.webp', 'https://www.flickr.com/photos/zaragozaantigua/50441583651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24919, 'Caesaraugusta siglo III', '"Caesaraugusta", dibujo de Jos‚îú¬Æ Luis Cano que representa la puerta norte de la muralla romana junto al Ebro, de la que parte el Cardo M‚îú√≠ximo. Fuente: "Zaragoza nuestra ciudad", Ayuntamiento de Zaragoza, 1983.', 250, 200, 299, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65639400, -0.87597000, '0101000020E61000002BDEC83CF207ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32068571131.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32068571131.webp', 'https://www.flickr.com/photos/zaragozaantigua/32068571131/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25063, 'Pedro Arbu‚îú¬Æs 1485', 'El martirio de san Pedro de Arbu‚îú¬Æs. Bartolom‚îú¬Æ Esteban Murillo, 1664. Pedro Arbu‚îú¬Æs era Inquisidor General del Reino de Arag‚îú‚îÇn, nombrado por Torquemada en 1484. Su labor fue muy contestada. El 14 de septiembre de 1485, mientras rezaba arrodillado ante el altar mayor de La Seo, fue acuchillado por un grupo de personas. Muri‚îú‚îÇ tres d‚îú¬°as despu‚îú¬Æs. En 1867 fue canonizado.', 1485, 1485, 1485, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65478000, -0.87577400, '0101000020E6100000C2FC15325706ECBF9609BFD4CFD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14994371585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14994371585.webp', 'https://www.flickr.com/photos/zaragozaantigua/14994371585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23107, 'The Cure 2000', 'Robert Smith, l‚îú¬°der del grupo musical brit‚îú√≠nico The Cure, actuando en la Sala Multiusos el 29 de marzo de 2000. Fuente: Agencia EFE.', 2000, 2000, 2000, 'Siglo XXI', 'UNIVERSIDAD', 41.63777500, -0.90069700, '0101000020E6100000B75ED38382D2ECBF6B9A779CA2D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24536064562.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24536064562.webp', 'https://www.flickr.com/photos/zaragozaantigua/24536064562/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25110, 'Catedral de La Seo 1813', 'Edward Hawke Locker estuvo en Espa‚îú‚ñía como secretario de la flota brit‚îú√≠nica del Mediterr‚îú√≠neo en el oto‚îú‚ñío de 1813, y en plena guerra pudo visitar, acompa‚îú‚ñíando al ej‚îú¬Ærcito del Mariscal de Campo Arthur Wellesley, algunas provincias espa‚îú‚ñíolas del interior, como Zaragoza, en la que estuvo poco despu‚îú¬Æs de la salida de las tropas francesas, recogiendo estampas gr‚îú√≠ficas, como la que ilustra esta entrada. En ella, aparece la fachada de la catedral de San Salvador, el Arco del Arzobispo, y la fachada del Palacio Arzobispal, que entonces a‚îú‚ïën presentaba esa llamativa esquina de acceso desde la plaza de la Seo, cuando el edificio de la antigua Diputaci‚îú‚îÇn del Reino no estaba alineado con el Palacio Arzobispal. "Vistas de Espa‚îú‚ñía" fue el resultado de este viaje de Locker, publicado por entregas casi inmediatamente. En 1824 se edit‚îú‚îÇ como libro, y de all‚îú¬° procede esta imagen. Fuente visual: Edward Hawke Locker, 1824, Cathedral del Seu: Zaragoza. Fondo Documental Hist‚îú‚îÇrico de las Cortes de Arag‚îú‚îÇn.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65501400, -0.87602500, '0101000020E61000000E4FAF946508ECBF0936AE7FD7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877516232.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877516232.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877516232/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25115, 'Interior de la Seo 1909', '"Saragossa. In the old Cathedral", Collins, W. W., 1909 Fotograbado a color Fuente: "Cathedral cities of Spain".', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65457900, -0.87545400, '0101000020E610000054E0641BB803ECBFFED2A23EC9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15064311095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15064311095.webp', 'https://www.flickr.com/photos/zaragozaantigua/15064311095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25141, '&quot;Cathedral del Seu&quot; 1813', 'Edward Hawke Locker estuvo en Espa‚îú‚ñía como secretario de la flota brit‚îú√≠nica del Mediterr‚îú√≠neo en el oto‚îú‚ñío de 1813, y en plena guerra contra la Francia napole‚îú‚îÇnica pudo visitar, acompa‚îú‚ñíando al ej‚îú¬Ærcito del Mariscal de Campo Arthur Wellesley, algunas provincias espa‚îú‚ñíolas del interior, como Zaragoza, en la que estuvo poco despu‚îú¬Æs de la salida de las tropas francesas, recogiendo estampas gr‚îú√≠ficas, como la que ilustra esta entrada. En ella, aparece la fachada de la catedral de San Salvador, el Arco del Arzobispo, y la fachada del Palacio Arzobispal, que entonces a‚îú‚ïën presentaba una llamativa esquina de acceso desde la plaza de la Seo, cuando el edificio de la antigua Diputaci‚îú‚îÇn del Reino no estaba alineado con el Palacio Arzobispal. "Views in Spain" ("Vistas de Espa‚îú‚ñía") fue el resultado editorial de este viaje de Locker, publicado por entregas casi inmediatamente en Inglaterra. En 1824 se edit‚îú‚îÇ ya como libro, en Londres, por John Murray, y de all‚îú¬° procede esta imagen a color, que es una litograf‚îú¬°a realizada por James Duffield Harding. Fuente visual: Edward Hawke Locker, "Cathedral del Seu. Zaragoza", amablemente aportada por Jos‚îú¬Æ Luis Cintora, de su Archivo particular.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65498300, -0.87590900, '0101000020E6100000C0B4A84F7207ECBFCE37A27BD6D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23055255321.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23055255321.webp', 'https://www.flickr.com/photos/zaragozaantigua/23055255321/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25147, 'La Seo 1710', 'Dibujo de Jes‚îú‚ïës ‚îú√ºngel P‚îú¬Ærez Casas recreando el aspecto figurado que tendr‚îú¬°a la Seo antes de que le fuese adosada la portada barroca neocl‚îú√≠sica sobre la anterior, g‚îú‚îÇtico-mud‚îú¬Æjar.', 1710, 1710, 1710, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65518900, -0.87592400, '0101000020E61000001502B9C49107ECBF77D9AF3BDDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27940513550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27940513550.webp', 'https://www.flickr.com/photos/zaragozaantigua/27940513550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25418, 'Puente de Piedra c.1955', 'Imagen de un d‚îú¬°a de niebla en el puente de Piedra donde se encuentra con la ribera derecha, y entronca con el paseo de la Ribera (actual Echegaray y Caballero) y con la calle Don Jaime I (justo donde un se‚îú‚ñíor cruza por un imaginario paso de peatones, s‚îú‚îÇlo existente en la actualidad). La permanencia de los ra‚îú¬°les del tranv‚îú¬°a paralelos al r‚îú¬°o, un recuerdo de la l‚îú¬°nea de "Circunvalaci‚îú‚îÇn", clausurada en 1943, a‚îú‚ïën aguantar‚îú¬°a alg‚îú‚ïën quinquenio m‚îú√≠s. La imagen, en altura, se habr‚îú¬°a capturado desde el edificio arzobispal anexo al Palacio de la misma titularidad. Fuente visual: Archivo Coyne, en AHPZ.', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65639400, -0.87574200, '0101000020E6100000EA7937161406ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15795092596.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15795092596.webp', 'https://www.flickr.com/photos/zaragozaantigua/15795092596/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25425, 'Club N‚îú√≠utico 1966', 'Vista del puente de Piedra de Zaragoza, con el Club N‚îú√≠utico en el paseo de Echegaray y Caballero. Fuente: "Espa‚îú‚ñía, qu‚îú¬Æ hermosa eres", 1966.', 1966, 1966, 1966, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65654200, -0.87601100, '0101000020E6100000CFF57D384808ECBFA839799109D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19929585034.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19929585034.webp', 'https://www.flickr.com/photos/zaragozaantigua/19929585034/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25440, 'R‚îú¬°o Ebro 1955', 'Excepcional e ins‚îú‚îÇlita imagen del r‚îú¬°o Ebro capturada desde la orilla derecha, inmediata al medieval puente de Piedra, durante uno de esos prolongados y caniculares per‚îú¬°odos de tiempo en que el r‚îú¬°o parece bien poca cosa, aunque no lo sea. El bajo nivel de las aguas permite una interesante visual de las antiguas estacas de madera colocadas para crear un peque‚îú‚ñío azud que remansaba agua para los molinos que la energ‚îú¬°a del r‚îú¬°o impulsaba. Es tiempo, tambi‚îú¬Æn de pesca, y de moderados ba‚îú‚ñíos de sol. La navegaci‚îú‚îÇn parece poco probable. Esta captura fue realizada por el fot‚îú‚îÇgrafo franc‚îú¬Æs Jean Paul Margnac en el verano de 1955, durante su paso por la pen‚îú¬°nsula Ib‚îú¬Ærica, desde Par‚îú¬°s, y con destino hacia tierras m‚îú√≠s meridionales. Fuente visual: www.flickr.com/photos/jean-paul-margnac/26452547350/in/al...', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65635400, -0.87566400, '0101000020E6100000FC1A49827005ECBFA54C6A6803D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26695916553.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26695916553.webp', 'https://www.flickr.com/photos/zaragozaantigua/26695916553/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25496, 'La Seo 1909', 'Archivo Conde de Polentinos. Aurelio de Colmenares y Orgaz. 1894-1935 "Fachada la Parroquieta capilla sepulcral de Don Lope de Luna La Seo (Catedral del Salvador)". Imagen capturada desde la calle del Sepulcro. Tras el Arco del Arzobispo, la plaza de La Seo, la Lonja, y el Pilar.', 1909, 1909, 1909, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65502200, -0.87529000, '0101000020E6100000C381902C6002ECBF8C14CAC2D7D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14878114720.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14878114720.webp', 'https://www.flickr.com/photos/zaragozaantigua/14878114720/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25501, 'Puerta del ‚îú√ºngel 1493', '"Primera Puerta del ‚îú√ºngel", Antonio Callaved, 2011. Representaci‚îú‚îÇn idealizada de la "Primera Puerta del ‚îú√ºngel", que cerraba Zaragoza en el per‚îú¬°metro de la muralla, zona norte. Fue reconstruida en 1523. Fuente: pinturascallaved.wordpress.com/5-mi-pintura-en-la-filatelia/', 1493, 1493, 1493, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65617300, -0.87588000, '0101000020E61000002C0E677E3507ECBF55C2137AFDD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15278414822.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15278414822.webp', 'https://www.flickr.com/photos/zaragozaantigua/15278414822/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23123, 'Metallica 2004', 'Foto: Juan Carlos Arcos. El cantante del grupo estadounidense de heavy metal Metallica, James Hetfield, actuando en La Romareda el 19 de junio de 2004. Fuente: Heraldo de Arag‚îú‚îÇn.', 2004, 2004, 2004, 'Siglo XXI', 'UNIVERSIDAD', 41.63655900, -0.90191300, '0101000020E6100000BCCADAA678DCECBFBB7CEBC37AD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31131931123.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31131931123.webp', 'https://www.flickr.com/photos/zaragozaantigua/31131931123/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25506, 'Llegada de Santiago, 1490', 'Viaje de Santiago desde Jerusal‚îú¬Æn a Zaragoza (1490). Sarga o tapiz conservada en la sacrist‚îú¬°a del Pilar de Zaragoza que representa al ap‚îú‚îÇstol llegando a la ciudad en el a‚îú‚ñío 40, aunque la representaci‚îú‚îÇn de la puerta del Puente en la muralla corresponde a la ‚îú¬Æpoca en que fue realizada la imagen. Fuente: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1490, 1490, 1490, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65605400, -0.87591000, '0101000020E6100000D6A887687407ECBF7A34D593F9D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16270192280.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16270192280.webp', 'https://www.flickr.com/photos/zaragozaantigua/16270192280/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25507, 'Basilio Boggiero 1809', 'Dibujo de Manuel Lahoz, 1959. Del libro "Los escolapios y los Sitios de Zaragoza", 1959. Recreaci‚îú‚îÇn de la muerte del sacerdote consejero del General Palafox, el sacerdote Basilio Boggiero, durante el sitio de Zaragoza de 1809. Se reproduce la puerta del ‚îú√ºngel al fondo y dos de los leones del puente de Piedra por los suelos. Fuente: www.asociacionlossitios.com/padreboggiero.htm', 1809, 1809, 1809, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65639400, -0.87574200, '0101000020E6100000EA7937161406ECBF33A5F5B704D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19083607386.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19083607386.webp', 'https://www.flickr.com/photos/zaragozaantigua/19083607386/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25648, 'Vista desde la Seo 1922', 'AHPZ. Archivo Fotogr‚îú√≠fico Julio Requejo. 05/06/1922. "Vista general desde L''Aseo [La Seo]". Torre de San Gil. Edificio de viviendas de Francisco Albi‚îú‚ñíana. Espoz y Mina. Don Jaime. Iglesia de Santa Cruz. Al fondo, Santiago el Mayor. Real Casa de la Misericordia. San Felipe. Et caetera.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65495800, -0.87581000, '0101000020E6100000F44F70B1A206ECBF7520EBA9D5D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14937864035.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14937864035.webp', 'https://www.flickr.com/photos/zaragozaantigua/14937864035/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20874, 'Puerta del Puente c.1150', 'Letra capitular que aparece en el tomo V del cartulario o Privilegios de la ciudad de Zaragoza (1549-1552). La iconograf‚îú¬°a utilizada copia documentos m‚îú√≠s antiguos. En la miniatura se ve la puerta del Puente (luego del ‚îú√ºngel), la muralla y el puente de madera altomedieval. En 1188, el puente dej‚îú‚îÇ de ser de madera. Hasta el siglo XV no se construy‚îú‚îÇ el que perdura hoy, llamado de las piedras o de Piedra. Fuente: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1150, 1150, 1150, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65662200, -0.87575300, '0101000020E6100000E4F6CB272B06ECBFC4EA8F300CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15834829934.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15834829934.webp', 'https://www.flickr.com/photos/zaragozaantigua/15834829934/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21007, 'Puente de Piedra 1860', '"Puente sobre el Ebro". Una de las fotos m‚îú√≠s antiguas del Pilar de Zaragoza, sin la gran c‚îú‚ïëpula central. El puente de Piedra todav‚îú¬°a presenta las pilastras pares acondicionadas como antiguas viviendas. Fuente visual: Charles Clifford, en Biblioteca Nacional de Espa‚îú‚ñía.', 1860, 1860, 1860, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14917766140.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14917766140.webp', 'https://www.flickr.com/photos/zaragozaantigua/14917766140/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21025, 'El Pilar 1868', 'Recuerda Benito P‚îú¬Ærez Gald‚îú‚îÇs en sus "Memorias de un desmemoriado", que en 1868, con motivo de la Exposici‚îú‚îÇn Aragonesa celebrada ese a‚îú‚ñío en Zaragoza, se curs‚îú‚îÇ invitaci‚îú‚îÇn oficial a los generales Serrano y Topete, como protagonistas de la "Gloriosa" revoluci‚îú‚îÇn que acababa de derribar del trono a los Borbones. Gald‚îú‚îÇs, en su calidad de periodista, form‚îú‚îÇ parte de la comitiva que lleg‚îú‚îÇ desde Madrid en tren a Campo Sepulcro. La recepci‚îú‚îÇn popular fue memorable, con cabalgatas, discursos, aclamaciones, m‚îú‚ïësicas, algarab‚îú¬°as varias, funci‚îú‚îÇn teatral en el Principal, banquete... Al d‚îú¬°a siguiente, Gald‚îú‚îÇs pase‚îú‚îÇ por la ciudad "sin gu‚îú¬°a", en un periplo que le llev‚îú‚îÇ por el Coso, el Mercado, el Pilar, y la Seo. M‚îú√≠s tarde, continu‚îú‚îÇ por la Torre Nueva, la Escuela P‚îú¬°a, y San Pablo. Al d‚îú¬°a siguiente, por la puerta del Carmen, la Trinidad, la Aljafer‚îú¬°a, subi‚îú‚îÇ hasta el Torrero, y luego baj‚îú‚îÇ hasta las ruinas de San Agust‚îú¬°n. La imagen reproduce el dibujo que Gald‚îú‚îÇs realiz‚îú‚îÇ "a pluma" desde la margen izquierda del Ebro, donde el antiguo convento de San L‚îú√≠zaro, capturando una reconocible y familiar vista parcial del puente de Piedra, con el templo del Pilar al fondo. Fuente visual: Revista "La Esfera" (Madrid).', 1868, 1868, 1868, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22320420423.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22320420423.webp', 'https://www.flickr.com/photos/zaragozaantigua/22320420423/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21047, 'Puente de Piedra 1871', 'Avenida del r‚îú¬°o Ebro a su paso por el puente de Piedra de Zaragoza. [1871] Vista copiada del natural, la madrugada del 13 de enero de 1871. Fuente: A.M.Z. Sign. 0838.', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65711900, -0.87541000, '0101000020E61000006CEC12D55B03ECBF454AB3791CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14672303708.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14672303708.webp', 'https://www.flickr.com/photos/zaragozaantigua/14672303708/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21053, 'Arrabal 1871', 'A.M.Z. Sign. 0837. Avenida del r‚îú¬°o Ebro a su paso por Zaragoza. [1871]. Lanchas prestando auxilio a los habitantes del Arrabal. Vista tomada del natural de la crecida del r‚îú¬°o Ebro del a‚îú‚ñío 1871.', 1871, 1871, 1871, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65812900, -0.87498700, '0101000020E6100000D89AADBCE4FFEBBF4CC631923DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14835923456.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14835923456.webp', 'https://www.flickr.com/photos/zaragozaantigua/14835923456/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21060, 'Vista desde Altab‚îú√≠s c.1877', 'Archivo RUIZ VERNACCI, Jean Laurent y C‚îú¬°a. 1872-1879. "Vista general desde Altabas", parte 3.', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65792400, -0.87449600, '0101000020E61000003B730F09DFFBEBBF73A087DA36D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14866379845.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14866379845.webp', 'https://www.flickr.com/photos/zaragozaantigua/14866379845/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21083, '&quot;Puente Pietra&quot;, c.1878', 'Imagen titulada "The city of Saragossa. Bridge Puente Pietra", que resulta beber de las mismas fuentes que la tercera de las tres vistas capturadas por Jean Laurent y C‚îú¬°a. hacia 1873, y que forman el extraordinario tr‚îú¬°ptico "Vista general desde Altabas". Esta toma se centra en el puente de Piedra, y la fachada de la ciudad al Ebro desde las Casas Consistoriales, hasta el barrio de San Pablo. La gran c‚îú‚ïëpula central del Pilar, y las c‚îú‚ïëpulas del Coro, terminadas.', 1878, 1878, 1878, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65735600, -0.87530500, '0101000020E610000018CFA0A17F02ECBF29EACC3D24D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26584473426.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26584473426.webp', 'https://www.flickr.com/photos/zaragozaantigua/26584473426/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21094, 'Pilar decimon‚îú‚îÇnico, 1880', 'Ayuntamiento de Zaragoza/L‚îú¬Æon & L‚îú¬Ævy. 1880. Nuestra Se‚îú‚ñíora del Pilar, vista desde el Puente de Piedra. La gran c‚îú‚ïëpula central del Pilar y las cuatro peque‚îú‚ñías que rodean la del coro, hab‚îú¬°an sido levantadas recientemente seg‚îú‚ïën proyecto de Jos‚îú¬Æ Yarza y J. A. Atienza, entre 1866 y 1872.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65747500, -0.87514000, '0101000020E6100000707CED992501ECBF03780B2428D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14722681348.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14722681348.webp', 'https://www.flickr.com/photos/zaragozaantigua/14722681348/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21100, 'Puente de Piedra 1880', 'As‚îú¬° luc‚îú¬°a el Puente de Piedra en una gu‚îú¬°a de viaje inglesa de 1880 titulada "Spanish pictures drawn with pen and pencil", si bien era una copia, con sus licencias y modificaciones, del dibujo que Eduard Hanke Locker hab‚îú¬°a realizado en 1813. Para los editores de la obra, ilustrar con im‚îú√≠genes de hac‚îú¬°a 67 a‚îú‚ñíos una obra actual, era normal. Como con la literatura oral, una copia de una copia puede acabar modificando bastante la realidad que pretende capturar. Las fuentes orales, y los dibujos, son as‚îú¬°.', 1880, 1880, 1880, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15951919945.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15951919945.webp', 'https://www.flickr.com/photos/zaragozaantigua/15951919945/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21160, 'Puente de Piedra 1890', '"Saragossa", ‚îú‚îÇleo sobre lienzo, Frank Brangwyn, 1890. Puente de Piedra de Zaragoza; al fondo, la Lonja y el Pilar. Fuente: www.bridgemanimages.com/', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20279883514.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20279883514.webp', 'https://www.flickr.com/photos/zaragozaantigua/20279883514/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21223, 'El puente de Piedra c.1906', '"Puente de Piedra", An‚îú‚îÇnimo, Ca.1906. Imagen del puente de Piedra capturado desde el Arrabal, con interesantes aspectos: a la Lonja siguen adosadas las antiguas "Casas de la Puente", luego "Casas Consistoriales", o Ayuntamiento, en estado casi terminal (el edificio, no la instituci‚îú‚îÇn) unos a‚îú‚ñíos antes de trasladarse de ubicaci‚îú‚îÇn a la plaza de la Libertad, y ser derribadas estas viejas construcciones. A su lado, el palacio de los Marqueses de Ayerbe. La segunda torre del Pilar, en proceso de ser construida desde 1903, dise‚îú‚ñíada por Jos‚îú¬Æ de Yarza y Ricardo Magdalena, y decorada con relieves de Dionisio Lasu‚îú¬Æn. Por el puente traquetea un electrificado tranv‚îú¬°a, a‚îú‚ïën en v‚îú¬°a ‚îú‚ïënica, de la L‚îú¬°nea del Arrabal. Fuente visual: Francisco Mar‚îú¬°n Bag‚îú‚ïù‚îú¬Æs: su tiempo y su ciudad.', 1906, 1906, 1906, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16102519604.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16102519604.webp', 'https://www.flickr.com/photos/zaragozaantigua/16102519604/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21243, 'Puente de Piedra c.1900', 'Vista del Puente de Piedra de Zaragoza desde el paseo del Ebro. Al fondo, el Cuartel de San L‚îú√≠zaro.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65723200, -0.87536700, '0101000020E61000009AEC9FA70103ECBF3DF19C2D20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20089723001.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20089723001.webp', 'https://www.flickr.com/photos/zaragozaantigua/20089723001/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21253, 'Puente de Piedra 1903', 'La "Perfumerie Xerol" encarg‚îú‚îÇ a "La Grande Imprimerie for‚îú¬Æzienne" de Paul-Emile Roustan, de Ru‚îú√≠n, una colecci‚îú‚îÇn de postales para promocionar la marca. Roustan fue otro de los franceses pioneros de la fotograf‚îú¬°a, m‚îú√≠s centrado en la publicidad comercial. As‚îú¬°, realiz‚îú‚îÇ una serie sobre "Espagne" que incluy‚îú‚îÇ esta convencional imagen del Puente de Piedra y el templo del Pilar desde la margen izquierda, junto al cuartel de San L‚îú√≠zaro, interesante por ser realizada antes de que se construyera el gran murall‚îú‚îÇn en piedra como protecci‚îú‚îÇn frente al Ebro. Lo que aqu‚îú¬° aparece es el previo terrapl‚îú¬Æn o escombrera. Al otro lado del Ebro, vista de la ciudad, con detalle de la veterana Casa Consistorial en las traseras de la Lonja.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20470946300.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20470946300.webp', 'https://www.flickr.com/photos/zaragozaantigua/20470946300/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21303, 'Puente de Piedra c.1900', 'Imagen del puente de Piedra editada con fines comerciales, con su aspecto integral de orilla a orilla, capturada desde el puente de Hierro. A la izquierda, la margen derecha, con algunos restos del antiguo puente de Tablas, en primer plano. A la derecha, la margen izquierda, con el arranque edilicio de la calle de Sobrarbe. Fuente visual: fototipia Hauser y Menet, AMZ.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33790629975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33790629975.webp', 'https://www.flickr.com/photos/zaragozaantigua/33790629975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21325, 'Ebro y Pilar 1903', 'Imagen capturada desde cierta altura junto al cuartel de San L‚îú√≠zaro ubicado donde el antiguo convento mercedario, con una vista panor‚îú√≠mica coloreada en tono mayormente gris que comprende el Puente de Piedra, el r‚îú¬°o Ebro y la fachada ribere‚îú‚ñía de la margen derecha desde la Casa Consisiorial y su anexo en La Lonja (a la izquierda), hasta la iglesia parroquial de San Juan de los Panetes (a la derecha). En el centro de la escena, el palacio de los marqueses de Ayerbe, el Colegio de los Infantes y el templo del Pilar con su antigua torre de Santiago o del suroeste, recrecida una d‚îú¬Æcada antes. Junto al arranque de la torre de Nuestra Se‚îú‚ñíora del Pilar, recrecida poco despu‚îú¬Æs, una vista ins‚îú‚îÇlita de la c‚îú‚ïëpula de la iglesia del antiguo convento de San Ildefonso. La fluida circulaci‚îú‚îÇn rodada por el Puente de Piedra, en este caso no cuenta con la compa‚îú‚ñí‚îú¬°a de alg‚îú‚ïën tranv‚îú¬°a de la l‚îú¬°nea del Arrabal, ya electrificada, que daba servicio a la margen izquierda.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65766700, -0.87519400, '0101000020E61000003CF9F4D89601ECBF4754A86E2ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49289177631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49289177631.webp', 'https://www.flickr.com/photos/zaragozaantigua/49289177631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21357, 'Puente de Piedra 1900', 'Imagen capturada a espaldas del cuartel de infanter‚îú¬°a de San L‚îú√≠zaro y centrada en el Puente de Piedra con el fondo edilicio de la ciudad desde la Casa Consistorial y la Lonja, a la izquierda, hasta el templo del Pilar.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65745900, -0.87526900, '0101000020E6100000E57B46223402ECBFFEBAD39D27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54784347558.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54784347558.webp', 'https://www.flickr.com/photos/zaragozaantigua/54784347558/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21428, 'Puente de Piedra c.1918', 'Imagen centrada en el puente de Piedra y el r‚îú¬°o Ebro, con el tel‚îú‚îÇn del fondo del templo del Pilar. Sobre el puente transita un tranv‚îú¬°a de la el‚îú¬Æctrica serie "Primitivos" (1-20), en servicio en la l‚îú¬°nea "G‚îú√≠llego", regresando desde la terminal de la carretera de Barcelona junto al puente de Santa Isabel. Fuente visual: "Zaragoza. El Pilar y el puente de piedra", postal en www.ebay.es/', 1918, 1918, 1918, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33664321024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33664321024.webp', 'https://www.flickr.com/photos/zaragozaantigua/33664321024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21458, 'R‚îú¬°o Ebro 1915', 'Imagen capturada desde la altura de la torre oriental o de N‚î¨¬¨. S‚î¨¬¨. del Pilar del hom‚îú‚îÇnimo templo, y centrada en una vista del tramo del r‚îú¬°o Ebro comprendido entre el puente de Piedra y el puente "de Hierro". En la margen izquierda, el cuartel de San L‚îú√≠zaro como fachada ribere‚îú‚ñía del barrio de Jes‚îú‚ïës, destacando el que fuera antiguo refectorio del convento mercedario que all‚îú¬° estuviera enclavado anta‚îú‚ñío. En primer t‚îú¬Ærmino y a la derecha, en la esquina del paseo del Ebro con la calle de Fernando el Cat‚îú‚îÇlico, solar donde estuviera la antigua Casa Consistorial, en proceso de derribo adjudicado por 4.250 pesetas a la empresa de do‚îú‚ñía Joaquina Candao, se‚îú‚ñíora viuda de Vicente. Desde 1912 el Ayuntamiento estaba ubicado en el edificio de la antigua Academia Militar sita en la plaza de Santo Domingo, y all‚îú¬° seguir‚îú¬°a por casi medio siglo.', 1915, 1915, 1915, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65676900, -0.87577300, '0101000020E6100000AB0837195506ECBF6803B00111D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52142695042.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52142695042.webp', 'https://www.flickr.com/photos/zaragozaantigua/52142695042/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21459, 'C‚î¨‚ïë. de Juslibol 1911', 'Imagen del arranque del camino de Juslibol junto al puente de Piedra y el principio de la calle del Sobrarbe (a la derecha y fuera de plano) y centrada en el "hospital de sangre" del Arrabal establecido por la Comisi‚îú‚îÇn provincial de la Cruz Roja en la farmacia de la viuda de S‚îú√≠nchez de Rojas durante la huelga general convocada a principios del oto‚îú‚ñío de ese a‚îú‚ñío, en previsi‚îú‚îÇn de alguna "alteraci‚îú‚îÇn de orden p‚îú‚ïëblico". Custodiado por varias parejas de guardiaciviles, este fue uno de los ocho "hospitales de sangre" habilitados en Zaragoza para la ocasi‚îú‚îÇn. A la izquierda e inmediato, el antiguo Almac‚îú¬Æn de salvados y semillas de Alejandro Chacen, y al fondo, vista parcial del extenso huerto de Juan Guitar, que se extend‚îú¬°a hasta el principio del camino de Ranillas, donde el lavadero de Agust‚îú¬°n Alcrudo. En primer t‚îú¬Ærmino, ni‚îú‚ñías provenientes de la escuela municipal ubicada en la calle de Pedro Villacampa, antigua del Tejar.', 1911, 1911, 1911, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65846900, -0.87470000, '0101000020E61000005AF5B9DA8AFDEBBF043752B648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52180142959.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52180142959.webp', 'https://www.flickr.com/photos/zaragozaantigua/52180142959/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21461, 'C‚î¨‚ïë. de Juslibol 1911', 'Imagen en acusado claroscuro capturada en el arranque del camino de Juslibol junto al puente de Piedra y centrada en un cacheo rutinario realizado por los guardiaciviles all‚îú¬° apostados durante la huelga general convocada a principios del oto‚îú‚ñío de ese a‚îú‚ñío, en previsi‚îú‚îÇn de alguna "alteraci‚îú‚îÇn de orden p‚îú‚ïëblico". Custodiaban adem‚îú√≠s uno de los ocho "hospitales de sangre" habilitados en Zaragoza para la ocasi‚îú‚îÇn por la Comisi‚îú‚îÇn provincial de la Cruz Roja, en este caso el situado en la farmacia de la viuda de S‚îú√≠nchez de Rojas, justo a espaldas del fot‚îú‚îÇgrafo. Tras la escena de primer t‚îú¬Ærmino, un tranv‚îú¬°a el‚îú¬Æctrico de la l‚îú¬°nea Arrabal, procedente de la plaza de la Constituci‚îú‚îÇn, casi termina de cruzar el puente de Piedra y se encamina a la calle del Sobrarbe. Al fondo y en la margen derecha se destacan las torres de la iglesia de San Nicol‚îú√≠s de Bari y la parroquial de Santa Mar‚îú¬°a Magdalena, adem‚îú√≠s de un torre‚îú‚îÇn del palacio Arzobispal y el cimborrio de la Seo.', 1911, 1911, 1911, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65846900, -0.87470000, '0101000020E61000005AF5B9DA8AFDEBBF043752B648D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/52189034602.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/52189034602.webp', 'https://www.flickr.com/photos/zaragozaantigua/52189034602/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21465, 'Arrabal 1911', 'Imagen capturada en el despejado entorno del Arrabal inmediato al puente de Piedra. La valla de madera del fondo oculta el terreno propiedad de la jefatura provincial de Obras P‚îú‚ïëblicas delimitado entre el puente y el cuartel de infanter‚îú¬°a, donde desde 1906 se estaba construyendo el pretil o muro de San L‚îú√≠zaro. Sobre la valla y a la derecha emerge el cimborrio de La Seo, y en el centro el remate de la torre de Santa Mar‚îú¬°a Magdalena. La imagen recoge algunos cacheos realizados por polic‚îú¬°as encubiertos durante la Huelga General de septiembre de 1911, al objeto de tratar de impedir el tr‚îú√≠nsito de huelguistas y controlar el acceso al puente desde el Arrabal.', 1911, 1911, 1911, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65811600, -0.87467900, '0101000020E61000007CEF6FD05EFDEBBFB77C24253DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53454554622.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53454554622.webp', 'https://www.flickr.com/photos/zaragozaantigua/53454554622/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21470, 'Puente de Piedra 1912', 'Imagen del Puente de Piedra con su aspecto tras la eliminaci‚îú‚îÇn del antiguo pretil de piedra a finales de la d‚îú¬Æcada anterior, sustituido por una lateral y volada plataforma construida en hormig‚îú‚îÇn armado y cerrada con barandilla met‚îú√≠lica que desde entonces soportaba el paso peatonal dejando as‚îú¬° el ancho del puente para tr‚îú√≠nsito rodado. En la margen izquierda destaca el reci‚îú¬Æn terminado pretil de San L‚îú√≠zaro, y tras ‚îú¬Æl destacan las torres de la iglesia parroquial de N.‚î¨¬¨ S.‚î¨¬¨ de Altab‚îú√≠s en la calle del Sobrarbe.', 1912, 1912, 1912, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65713800, -0.87545100, '0101000020E61000001004C8D0B103ECBFBC7A15191DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53571283335.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53571283335.webp', 'https://www.flickr.com/photos/zaragozaantigua/53571283335/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21526, 'Puente de Piedra 1925', 'Imagen est‚îú√≠ndar, tomada desde el cuartel de San L‚îú√≠zaro, del r‚îú¬°o Ebro, el puente de Piedra, y la ribera derecha centrada en la ic‚îú‚îÇnica silueta del templo de El Pilar. Fuente visual: Fundaci‚îú‚îÇn Telef‚îú‚îÇnica', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17021424755.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17021424755.webp', 'https://www.flickr.com/photos/zaragozaantigua/17021424755/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21529, 'Zaragoza 1929', 'Cartel publicitario del Ferrocarril de Canfranc, representando la ciudad de Zaragoza, dise‚îú‚ñíado por ‚îú√´mile Paul Champseix.', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65714800, -0.87534800, '0101000020E6100000EACE13CFD902ECBFDF50F86C1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18956040315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18956040315.webp', 'https://www.flickr.com/photos/zaragozaantigua/18956040315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21536, 'Puente de Piedra 1925', 'Imagen del Puente de Piedra capturada desde el Puente de Hierro. Fuente visual: fotograf‚îú¬°a Jos‚îú¬Æ Ortiz Echag‚îú‚ïùe ("Espa‚îú‚ñía. Pueblos y paisajes", San Sebasti‚îú√≠n, 1942). Amablemente aportada por Mariano Lacruz P‚îú¬Ærez.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65715100, -0.87470200, '0101000020E610000087DD770C8FFDEBBF50C422861DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19657727972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19657727972.webp', 'https://www.flickr.com/photos/zaragozaantigua/19657727972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21588, 'Calle Sobrarbe c.1923', 'Calle del Sobrarbe desde el puente de Piedra, con la iglesia de Altab‚îú√≠s al fondo. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65827500, -0.87471200, '0101000020E61000006B662D05A4FDEBBF2063EE5A42D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24802773091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24802773091.webp', 'https://www.flickr.com/photos/zaragozaantigua/24802773091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21589, 'Puente de Piedra c.1920', 'Vista lateral del puente de Piedra. Al fondo, el cuartel de San L‚îú√≠zaro. Fuente: Foto Jes‚îú‚ïës Corm‚îú√≠n. AMZ.', 1920, 1920, 1920, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65678300, -0.87547400, '0101000020E61000001BF2CF0CE203ECBFCDC8207711D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24803124631.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24803124631.webp', 'https://www.flickr.com/photos/zaragozaantigua/24803124631/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21605, 'Puente de Piedra c.1925', 'Vista del Puente de Piedra sobre el r‚îú¬°o Ebro con el Arrabal al fondo. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65713600, -0.87543200, '0101000020E610000060E63BF88903ECBF1B834E081DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27404057565.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27404057565.webp', 'https://www.flickr.com/photos/zaragozaantigua/27404057565/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21623, 'Calle de Sobrarbe c.1923', 'Imagen del arranque de la calle de Sobrarbe desde el puente de Piedra, ubicaci‚îú‚îÇn desde la que se habr‚îú¬°a capturado la fotograf‚îú¬°a. En el centro, la unidad 15 (serie "Primitivos") de la l‚îú¬°nea 4, o Arrabal, circula por la v‚îú¬°a doble de ese tramo de la calle Sobrarbe, embocada hacia la carretera de Huesca. A la derecha, el convento de Altab‚îú√≠s, y la iglesia parroquial hom‚îú‚îÇnima. A la izquierda, pretil sobre el paso del enlace ferroviario con la estaci‚îú‚îÇn del Norte, y antiguas parcelas del Arrabal. Fuente visual: "Zaragoza 1908-2008. Arquitectura y Urbanismo".', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65843100, -0.87462400, '0101000020E6100000997E8978EBFCEBBF17D68D7747D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33844622362.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33844622362.webp', 'https://www.flickr.com/photos/zaragozaantigua/33844622362/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21650, 'Puente de Piedra, c.1925', 'Arrabalera imagen capturada en la ribera izquierda del r‚îú¬°o Ebro, donde la arboleda de Macanaz arranca desde el Puente de Piedra. Esta pionera zona verde fue plantada a principios del siglo XVIII como escudo natural ante las riadas que asolaban esta zona de la margen fluvial siniestra cada vez que el Ebro se sal‚îú¬°a de madre. Entre los ‚îú√≠lamos, improvisado tendedero utilizado por los habitantes de las precarias infraviviendas del entorno fluvial. Al fondo, el cuartel de infanter‚îú¬°a de san L‚îú√≠zaro, con vista del edificio del refectorio o comedor del antiguo convento mercedario reci‚îú¬Æn reconvertido en dependencias cuarteleras.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65808400, -0.87539700, '0101000020E61000004487C0914003ECBFAC02B5183CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51478807037.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51478807037.webp', 'https://www.flickr.com/photos/zaragozaantigua/51478807037/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21651, 'Arboleda de Macanaz c.1925', 'Imagen capturada en la arboleda de Macanaz, donde un grupo de n‚îú‚îÇmadas de procedencia centroeuropea y etnia gitana se hab‚îú¬°a establecido provisionalmente durante su paso por Zaragoza. Uno de ellos abre la puerta al objetivo del fot‚îú‚îÇgrafo para mostrarnos el interior de la infravivienda habilitada temporalmente entre los ‚îú√≠lamos de la arboleda. Al fondo y a la izquierda, varias personas contemplan el pasar del agua del r‚îú¬°o Ebro en las inmediaciones al puente de Piedra.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65820400, -0.87549400, '0101000020E6100000E2033BFE0B04ECBF560C570740D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51486872160.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51486872160.webp', 'https://www.flickr.com/photos/zaragozaantigua/51486872160/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21673, 'Regulares y legionarios 1938', 'AHP Huesca. Carlos Skogler. 1938. El ej‚îú¬Ærcito colonial espa‚îú‚ñíol en el Protectorado de Marruecos era, en julio de 1936, por su profesionalidad, dotaci‚îú‚îÇn en armamento y experiencia en acciones de guerra, la fuerza militar m‚îú√≠s preparada de todo el ej‚îú¬Ærcito de la Rep‚îú‚ïëblica. Su alineaci‚îú‚îÇn con los sublevados fue decisiva, primero, para que el fracasado golpe de Estado derivara en una guerra, y luego porque fue la m‚îú√≠s efectiva fuerza de choque de los nacionalistas hasta 1939. En la imagen, "regulares" (tropas ind‚îú¬°genas marroqu‚îú¬°es) y "legionarios" (Legi‚îú‚îÇn espa‚îú‚ñíola, o "Tercio de Extranjeros") del ej‚îú¬Ærcito colonial posando no muy relajados en el Puente de Piedra, con el fondo del Pilar. En la imagen se ha colado un tancredo, y un perro, que al parecer no fueron represaliados por ello.', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65717000, -0.87536900, '0101000020E6100000C7D45DD90503ECBFC7F484251ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14822133559.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14822133559.webp', 'https://www.flickr.com/photos/zaragozaantigua/14822133559/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21709, 'Puente de Piedra 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El t‚îú¬°tulo (la fuente visual as‚îú¬° lo cataloga) no se corresponde en absoluto con la captura, salvo que s‚îú¬° es Zaragoza: se trata de una imagen del puente de Piedra que, tomada muy cerca del puente de Hierro, es casi un panor‚îú√≠mica que abarca desde el inmenso Palacio Arzobispal (izquierda), hasta el antiguo Molino harinero y el cuartel de San L‚îú√≠zaro (derecha) Fuente visual: Fotograf‚îú¬°a de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65715400, -0.87536500, '0101000020E61000006C04E275FD02ECBFC1374D9F1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17166966630.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17166966630.webp', 'https://www.flickr.com/photos/zaragozaantigua/17166966630/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21711, 'Puente de Piedra 1933', '"El Canal Imperial i el riu Huerva (Saragossa)" El t‚îú¬°tulo (la fuente visual as‚îú¬° lo cataloga) no se corresponde con la captura, salvo en que s‚îú¬° es Zaragoza: se trata de una imagen parcial del puente de Piedra que, tomada desde la margen derecha, un poco por debajo del nivel del paseo de la Ribera, captura el entronque del puente con la ribera izquierda, con visual del muro p‚îú¬Ætreo de defensa fluvial de San L‚îú√≠zaro, el convento de Santa Isabel, y las torrecillas de la parroquia de Altab‚îú√≠s. Las viviendas chaflanean alabeadamente la calle Sobrarbe con la trinchera del ferrocarril que conecta la estaci‚îú‚îÇn del Norte con la de Delicias. Fuente visual: Fotograf‚îú¬°a de Gonzalo Reparaz Ruiz (cartotecadigital.icc.cat/)', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65808700, -0.87458400, '0101000020E61000000C5BB39597FCEBBF1D76DF313CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17354372691.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17354372691.webp', 'https://www.flickr.com/photos/zaragozaantigua/17354372691/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21764, 'Puente de Piedra 1932', 'Puente de Piedra con detalle del monumento en memoria de Basilio Boggiero, Santiago de Sas y el Bar‚îú‚îÇn de Warsage. Al fondo, el Pilar. Fuente visual: Foto Conrado Barl‚îú¬Æs, donada por Daniel Barl‚îú¬Æs y digitalizada por Jos‚îú¬Æ Luis Cintora para www.rafaelcastillejo.com', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22621297024.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22621297024.webp', 'https://www.flickr.com/photos/zaragozaantigua/22621297024/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21804, 'Vista de Zaragoza 1932', 'Litograf‚îú¬°a de Serge Rovinsky, con el puente de Piedra sobre el Ebro y la Seo y el Pilar al fondo. Fuente: Espagne grandiose et fantastique, Aulard, Par‚îú¬°s, 1932.', 1932, 1932, 1932, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65734300, -0.87523600, '0101000020E6100000F70489EDEE01ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27339675308.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27339675308.webp', 'https://www.flickr.com/photos/zaragozaantigua/27339675308/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21827, 'Sixto Celorrio 1933', 'Imagen de la esquinera y destacable fachada de la f‚îú√≠brica "Mosaicos Herrero", empresa reconocida en la ‚îú¬Æpoca por su participaci‚îú‚îÇn edilicia en la nueva estaci‚îú‚îÇn de Las Delicias, el Front‚îú‚îÇn Aragon‚îú¬Æs, el Front‚îú‚îÇn Jai Alai, la Academia General Militar, et alia. A la izquierda, el arranque de la calle de Demetrio Gal‚îú√≠n, redenominada Garc‚îú¬°a Arista tras el 18 de julio de 1936. Hacia la derecha, la calle de Sixto Celorrio. Este edificio no ha perdurado. Fuente visual: diario "El Noticiero". Archivo Jos‚îú¬Æ Mar‚îú¬°a Ballest‚îú¬°n Miguel.', 1933, 1933, 1933, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65927200, -0.87577200, '0101000020E6100000941458005306ECBF92955F0663D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32568372816.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32568372816.webp', 'https://www.flickr.com/photos/zaragozaantigua/32568372816/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21919, 'Calle del Sobrarbe 1939', 'Imagen capturada durante la matinal de Nochevieja del "A‚îú‚ñío de la Victoria" en el arranque de la calle del Sobrarbe y centrada en la gran cabalgata anunciadora de las fiestas del "XIX Centenario de la venida de la Virgen en carne mortal (sic) a Zaragoza". Compuesta por un heraldo encargado de entregar la Pastoral del Prelado donde se "invitaba a los fieles a participar en las solemnidades del centenario" a todas las parroquias de la ciudad, acompa‚îú‚ñíado por una vistosa comparsa de casi cincuenta figurantes "ricamente vestidos a la usanza imperial", unos a pie y la mayor‚îú¬°a a caballo. En este caso, la comitiva se dirige a cruzar el puente de Piedra de regreso a la urbe tras entregar la referida Pastoral a la arrabalera parroquia de N‚î¨¬¨. S‚î¨¬¨. de Altab‚îú√≠s. Al fondo, fachada ribere‚îú‚ñía de la margen derecha dominada por la mole del templo del Pilar.', 1939, 1939, 1939, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65834000, -0.87468900, '0101000020E6100000607825C973FDEBBF07D3307C44D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54235617941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54235617941.webp', 'https://www.flickr.com/photos/zaragozaantigua/54235617941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21961, 'R‚îú¬°o Ebro c.1942', 'Vista del r‚îú¬°o Ebro a su paso por el puente de Piedra de Zaragoza, desde el Pilar, y del barrio de Jes‚îú‚ïës en la Margen Izquierda, en los a‚îú‚ñíos 40. Fuente: rafaelcastillejo.com', 1942, 1942, 1942, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20711963635.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20711963635.webp', 'https://www.flickr.com/photos/zaragozaantigua/20711963635/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21983, 'Baturros 1949', 'Vista del Pilar desde la margen izquierda del r‚îú¬°o Ebro, donde posan unos baturros con burro. Para hacer m‚îú√≠s tradicional la imagen, un preciso retoque manual ha eliminado, a la izquierda, la nueva Casa Consistorial en obras. Fuente: www.facebook.com/photo.php?fbid=10210611074892567&set...', 1949, 1949, 1949, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65808100, -0.87545300, '0101000020E61000003EEC8502B603ECBF3B8F8AFF3BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28910045645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28910045645.webp', 'https://www.flickr.com/photos/zaragozaantigua/28910045645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22026, 'Puente de Piedra c.1944', 'Imagen capturada en el arranque de la avenida de Catalu‚îú‚ñía y la calle del Sobrarbe y orientada hacia el sur, con el fondo del templo del Pilar, cuando efectivos militares marchan en formaci‚îú‚îÇn sobre el puente de Piedra para dirigirse a realizar maniobras en los Pinares de Venecia. En primer t‚îú¬Ærmino, v‚îú¬°as de las l‚îú¬°neas del tranv‚îú¬°a 4. Arrabal, 9. G‚îú√≠llego y 10. Academia', 1944, 1944, 1944, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65829200, -0.87472200, '0101000020E61000004EEFE2FDB8FDEBBFF69B89E942D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50162258261.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50162258261.webp', 'https://www.flickr.com/photos/zaragozaantigua/50162258261/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22063, 'El Pilar 1956', 'Vuelta ciclista a Espa‚îú‚ñía, mayo de 1956. Paso por el puente de Piedra de los ciclistas participantes en la vuelta de 1956. Al fondo, el Pilar con sus dos torres en obras. Tambi‚îú¬Æn el ayuntamiento, en esqueleto a‚îú‚ïën. Fuente: elbalcondesanlazaro.blogspot.com.es/2013/12/la-vuelta-cic...', 1956, 1956, 1956, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65798400, -0.87487500, '0101000020E6100000E5D022DBF9FEEBBF48A5D8D138D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15045000974.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15045000974.webp', 'https://www.flickr.com/photos/zaragozaantigua/15045000974/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22072, 'Puente de Piedra a‚îú‚ñíos 50', 'Foto Luis Mompel/Heraldo de Arag‚îú‚îÇn, a‚îú‚ñíos 50 del siglo XX. Un grupo de personas intenta levantar un cuadr‚îú‚ïëpedo que parece haberse ca‚îú¬°do por el sobrepeso del carro que transporta, en el Puente de Piedra de Zaragoza. Al fondo a la derecha, las torres de la iglesia de Nuestra Se‚îú‚ñíora de Altab‚îú√≠s. Fuente: www.facebook.com/photo.php?fbid=4878857666515&set=o.6...', 1950, 1950, 1959, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65777000, -0.87499600, '0101000020E6100000A52F849CF7FFEBBF1C25AFCE31D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15470899799.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15470899799.webp', 'https://www.flickr.com/photos/zaragozaantigua/15470899799/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22111, 'Puente de Piedra c.1950', 'Desde el Arrabal y en el edificio de cuatro alturas que daba principio a la calle de Sixto Celorrio, una vista al inmediato punto donde comenzaban la avenida de Catalu‚îú‚ñía y la calle del Sobrarbe, cada una se‚îú‚ñíalada por su correspondiente tendido tranviario. Sobre el puente de Piedra transitan peatones, unos pocos veh‚îú¬°culos y un par de tranv‚îú¬°as de las cuatro l‚îú¬°neas que entonces lo cruzaban. Al fondo, la fachada del Casco Viejo al r‚îú¬°o Ebro de la que se destacan las torres de la Magdalena y de la iglesia del Real Seminario de San Carlos Borromeo, el cimborrio y la torre de la Seo, y la torre occidental de la iglesia del Sagrado Coraz‚îú‚îÇn de Jes‚îú‚ïës, en la plaza de San Pedro Nolasco. Al fondo, la plaza de La Seo, la Lonja y el ayuntamiento en construcci‚îú‚îÇn. Fuente visual: www.todocoleccion.net/', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22099641600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22099641600.webp', 'https://www.flickr.com/photos/zaragozaantigua/22099641600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22188, 'Puente de Piedra c.1950', 'Imagen capturada de forma muy creativa desde la altura de las antiguas viviendas que chaflaneaban el arranque de la calle de Sobrarbe, la zanja del enlace ferroviario, y el principio de la calle de Sixto Celorrio, con una interesante visual, en primer t‚îú¬Ærmino, del puente de Piedra y el terrapl‚îú¬Æn en descenso hasta el talud ferrovario. Al fondo, la margen derecha, con las destacadas obras de la nueva casa consistorial, y el t‚îú¬°mido comienzo del recrecimiento de la torre nororiental del Pilar. Fuente visual: www.ebay.es/', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65816600, -0.87496700, '0101000020E6100000128942CBBAFFEBBF69AB92C83ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32172079975.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32172079975.webp', 'https://www.flickr.com/photos/zaragozaantigua/32172079975/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22372, 'Vista a‚îú¬Ærea Ebro 1964', 'Vista a‚îú¬Ærea de Zaragoza desde el Ebro, pasando bajo el puente de Piedra. Al fondo, el paseo de la Independencia. Fuente: Colecci‚îú‚îÇn Rafael Margal‚îú¬Æ.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21695523153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21695523153.webp', 'https://www.flickr.com/photos/zaragozaantigua/21695523153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22377, 'Vista a‚îú¬Ærea Ebro 1964', 'Vista a‚îú¬Ærea del r‚îú¬°o Ebro a su paso por el centro de Zaragoza. Al fondo, el suroeste de la ciudad. Fuente: Colecci‚îú‚îÇn Rafael Margal‚îú¬Æ.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22289928516.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22289928516.webp', 'https://www.flickr.com/photos/zaragozaantigua/22289928516/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22398, 'Puente de Piedra 1969', 'Puente de Piedra desde el Arrabal. Al fondo, la fachada al Ebro del paseo de Echegaray y Caballero, desde Don Jaime I, hasta San Vicente de Pa‚îú‚ïël. Fuente visual: Foto Leonardo P‚îú¬Ærez Obis, donada por ‚îú√ºngel Hern‚îú√≠ndez Mostajo para www.rafaelcastillejo.com', 1969, 1969, 1969, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22852022870.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22852022870.webp', 'https://www.flickr.com/photos/zaragozaantigua/22852022870/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22512, 'Puente de Piedra 1964', 'Imagen centrada en el puente de Piedra sobre el r‚îú¬°o Ebro, con peatones cruzando por los laterales voladizos junto a la met‚îú√≠lica valla con funci‚îú‚îÇn quitamiedos, mientras por la calzada cruza tr‚îú√≠fico, incluso pesado. Sobre el puente, tendido utilizado por los tranv‚îú¬°as de las l‚îú¬°neas Arrabal y Academia, los trolebuses de la l‚îú¬°nea G‚îú√≠llego y los que regresaban del barrio de Jes‚îú‚ïës. Al fondo, panorama de antiguos edificios de vivienda en el arranque de la calle del Sobrarbe y junto al t‚îú‚ïënel del enlace ferroviario que pasaba por debajo, adem‚îú√≠s del convento de Altab‚îú√≠s, tras el que se ve parcialmente la iglesia del mismo nombre. En primer t‚îú¬Ærmino, los potentes tajamares del puente, poblados en su parte superior por vegetaci‚îú‚îÇn que encuentra acomodo casi en cualquier parte.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65681700, -0.87592300, '0101000020E6100000FE0DDAAB8F07ECBF793A579412D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51089274807.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51089274807.webp', 'https://www.flickr.com/photos/zaragozaantigua/51089274807/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22582, 'Riada Ebro 1978', 'Luis Serrano Pardo. 1978. Imagen, desde el puente de Hierro, de la riada que el mes de febrero de ese a‚îú‚ñío lleg‚îú‚îÇ a la ciudad. Desde la gran riada de 1961 el Ebro no hab‚îú¬°a bajado as‚îú¬°. Fuente: "El Ebro desbordado. Una historia de las crecidas del r‚îú¬°o en Zaragoza", Ayuntamiento de Zaragoza, 2011.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65715400, -0.87538600, '0101000020E61000004A0A2C802903ECBFC1374D9F1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15591636219.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15591636219.webp', 'https://www.flickr.com/photos/zaragozaantigua/15591636219/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22594, 'T‚îú‚ïënel de San L‚îú√≠zaro 1970', 'Vista de las v‚îú¬°as del enlace que conectaba la estaci‚îú‚îÇn del Arrabal con la estaci‚îú‚îÇn de Delicias. Al fondo, t‚îú‚ïënel de San L‚îú√≠zaro bajo la calle del Sobrarbe. El puente de Piedra queda a la izquierda. A la derecha, convento de las Terciarias franciscanas de Altab‚îú√≠s, por el que sobresale el moderno bloque del n‚î¨‚ïë 2 de la calle de Sixto Celorrio. Tras el desmantelamiento del tendido ferroviario, este t‚îú‚ïënel fue reutilizado por el tr‚îú√≠fico motorizado.', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65822000, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16804954258.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16804954258.webp', 'https://www.flickr.com/photos/zaragozaantigua/16804954258/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22695, 'Baturros y Pilar c.1972', 'Cuadro de jota en el pretil de San L‚îú√≠zaro. Detr‚îú√≠s, el puente de Piedra y el Pilar. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65800200, -0.87469000, '0101000020E6100000766C04E275FDEBBFEF59D76839D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27321088072.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27321088072.webp', 'https://www.flickr.com/photos/zaragozaantigua/27321088072/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22699, 'Puente de Piedra nocturno c.1972', 'El Pilar tras el Puente de Piedra, en imagen nocturna. A la izquierda, el Ayuntamiento. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65713600, -0.87543200, '0101000020E610000060E63BF88903ECBF1B834E081DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27385082936.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27385082936.webp', 'https://www.flickr.com/photos/zaragozaantigua/27385082936/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22726, 'Puente de Piedra 1972', 'Foto centrada en la unidad 72 de la l‚îú¬°nea de troleb‚îú‚ïës "Barrio Jes‚îú‚ïës", pasando por el puente de Piedra. Al fondo, torrecillas de la iglesia de Altab‚îú√≠s. Fuente: Colecci‚îú‚îÇn Daniel Andr‚îú¬Æs.', 1972, 1972, 1972, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65751000, -0.87539500, '0101000020E6100000179F02603C03ECBF8065A54929D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30552853664.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30552853664.webp', 'https://www.flickr.com/photos/zaragozaantigua/30552853664/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22835, 'Puente de Piedra c.1985', 'El puente de Piedra sobre el r‚îú¬°o Ebro, en una imagen que ilustra su papel como importante acceso rodado a la ciudad, antes de su remodelaci‚îú‚îÇn basada en un anteproyecto de 1982 y ejecutada en 1991, con direcci‚îú‚îÇn del arquitecto Jos‚îú¬Æ Manuel P‚îú¬Ærez Latorre. Dos carriles de circulaci‚îú‚îÇn rodada, con quitamiedos estilo autov‚îú¬°a para el tr‚îú√≠nsito de peatones, y se‚îú‚ñíalizaciones para ir al sureste, al centro, y al suroeste. Es decir, procediendo desde el norte, a todas partes. La disparatada hegemon‚îú¬°a del coche, llevada al paroxismo. Aunque la citada restauraci‚îú‚îÇn fue concebida para dejar el paso exclusivo para los peatones, el Ayuntamiento decidi‚îú‚îÇ que tambi‚îú¬Æn podr‚îú¬°an atravesarlo los autobuses urbanos y los taxis, por lo que fue necesario modificar el pavimento una vez acabada la obra, al no ser el adecuado. Al fondo, el palacio arzobispal, la torre de la Seo, la Lonja y el Ayuntamiento.', 1985, 1985, 1985, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65804400, -0.87480200, '0101000020E610000069368FC360FEEBBF1DAA29C93AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14763710599.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14763710599.webp', 'https://www.flickr.com/photos/zaragozaantigua/14763710599/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22841, 'Arrabal 1985', '1985. Arboleda de Macanaz, puente de Piedra y balc‚îú‚îÇn de San L‚îú√≠zaro.', 1985, 1985, 1985, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65806100, -0.87461300, '0101000020E61000009F01F566D4FCEBBFF3E2C4573BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14907942943.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14907942943.webp', 'https://www.flickr.com/photos/zaragozaantigua/14907942943/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22938, 'Puente de Piedra 1983', 'Puente de Piedra sobre el Ebro en su etapa de hegemon‚îú¬°a vial motorizada, con el fondo de la fachada ribere‚îú‚ñía desde la Lonja, a la derecha, pasando por la Seo, hasta la Magdalena. Se trata de una vi‚îú‚ñíeta del c‚îú‚îÇmic "Buscar a Efe" publicado por entregas en Andal‚îú√≠n, con gui‚îú‚îÇn de J. A. Labordeta, y dibujo de Isidro Ferrer. Fuente visual: "Andal‚îú√≠n, peri‚îú‚îÇdico quincenal aragon‚îú¬Æs".', 1983, 1983, 1983, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65711600, -0.87552000, '0101000020E610000031CEDF844204ECBFD4D688601CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32632047505.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32632047505.webp', 'https://www.flickr.com/photos/zaragozaantigua/32632047505/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23005, 'Puente de Piedra a‚îú‚ñíos 90', 'Vista del puente de Piedra tras su restauraci‚îú‚îÇn, con el Pilar al fondo. Fuente: Foto para postal de Comercial Josan. Cesi‚îú‚îÇn de la familia de Jos‚îú¬Æ Mar‚îú¬°a Sanz Gonz‚îú√≠lez a Rafael Castillejo. Dataci‚îú‚îÇn y procesado:', 1990, 1990, 1999, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65716800, -0.87541000, '0101000020E61000006CEC12D55B03ECBF26FDBD141ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/27422251265.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/27422251265.webp', 'https://www.flickr.com/photos/zaragozaantigua/27422251265/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23025, 'Vista a‚îú¬Ærea 1990', 'A‚îú¬Ærea visual capturada sobre el cauce del r‚îú¬°o Ebro y orientada hacia su curso superior, cruzado sucesivamente por los puentes de Piedra, Santiago y La Almozara. En primer y a la izquierda, solares de la plaza de San Bruno inmediatos al Palacio Arzobispal y obras arqueol‚îú‚îÇgicas en la plaza de La Seo y reforma de la plaza del Pilar. Hacia la derecha, el puente de Piedra durante su ‚îú‚ïëltima gran reforma inaugurada en abril de 1991.', 1990, 1990, 1990, 'Anos 90', 'CASCO HIST‚îú√¥RICO', 41.65691400, -0.87568700, '0101000020E6100000070951BEA005ECBF6C2409C215D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50201970418.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50201970418.webp', 'https://www.flickr.com/photos/zaragozaantigua/50201970418/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23075, 'Puente de Piedra 2004', 'Vicente Modesto Locual. 2004. A‚îú¬Ærea vista centrada en el Puente de Piedra, con una expositiva presencia, en primer plano, del templo de El PIlar, el Ayuntamiento, la Lonja, y las dependencias del arzobispado anexas a su Palacio. Al otro lado del Puente, la margen izquierda, con unas riberas al Ebro a‚îú‚ïën v‚îú¬°rgenes de intervenci‚îú‚îÇn: el Balc‚îú‚îÇn de San L‚îú√≠zaro, por ejemplo, parece un vergel. En el entorno de la calle Caminos del Norte (recuerdo del paso por ese lugar de los trenes que de la Estaci‚îú‚îÇn del Norte se dirig‚îú¬°an hacia Barcelona y Canfranc), mucha obra nueva (grandes bloques de viviendas), a‚îú‚ïën sin terminar.', 2004, 2004, 2004, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15428464161.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15428464161.webp', 'https://www.flickr.com/photos/zaragozaantigua/15428464161/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23180, 'Arrabal 2000', '"La margen izquierda", ‚îú‚îÇleo sobre lienzo, Ignacio Mayayo, 2000. Vista del r‚îú¬°o Ebro desde su margen derecha, entre los puentes de Piedra y de Hierro. La fachada al r‚îú¬°o del Arrabal que ofrece esta pintura ha sido modificada radicalmente desde entonces. Fuente: ignaciomayayo.com', 2000, 2000, 2000, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65789500, -0.87474300, '0101000020E61000002CF52C08E5FDEBBFD99942E735D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40405639694.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40405639694.webp', 'https://www.flickr.com/photos/zaragozaantigua/40405639694/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23261, 'Balsas de Ebro Viejo 1864', 'Interesante plano topogr‚îú√≠fico firmado por Antonio Vali‚îú¬Æn que representa los terrenos y riegos de los propietarios Manuel Ezmir, Pedro Labarta y Gregorio Lisa, sitos en el t‚îú¬Ærmino del Rabal, partida de las Balsas de Ebro Viejo. A la derecha, representaci‚îú‚îÇn del puente de Piedra sobre el r‚îú¬°o Ebro. En la parte superior, antigua calle del Rosario, que conduc‚îú¬°a a la hom‚îú‚îÇnima plaza del Rabal, y antigua calle de "canta-rranas", luego de las Ranas. En la parte inferior, camino de la Arboleda o de Ranillas junto a la arboleda de Macanaz. Fuente visual: Real Audiencia de Arag‚îú‚îÇn, AHPZ.', 1864, 1864, 1864, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65927200, -0.87577200, '0101000020E6100000941458005306ECBF92955F0663D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40066783175.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40066783175.webp', 'https://www.flickr.com/photos/zaragozaantigua/40066783175/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23812, 'El Pilar c.1904', 'Imagen capturada desde el puente de Piedra y centrada en el templo del Pilar con la torre de Nuestra Se‚îú‚ñíora del Pilar en construcci‚îú‚îÇn.', 1904, 1904, 1904, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65668700, -0.87594700, '0101000020E610000020F0C000C207ECBFAB5AD2510ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15725486376.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15725486376.webp', 'https://www.flickr.com/photos/zaragozaantigua/15725486376/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23875, 'El Pilar 1929', 'Pa‚îú‚ñío de azulejos de cer‚îú√≠mica representando a un aragon‚îú¬Æs que posa junto a la barandilla met‚îú√≠lica del puente de Piedra, con el Pilar y el Ebro al fondo. Situado en la puerta de Arag‚îú‚îÇn de la plaza de Espa‚îú‚ñía de Sevilla, construida con motivo de la Exposici‚îú‚îÇn Iberoamericana de 1929. Fuente: franconetti-aula-abierta.blogspot.com', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65717500, -0.87541000, '0101000020E61000006CEC12D55B03ECBFD95F764F1ED44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30949561710.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30949561710.webp', 'https://www.flickr.com/photos/zaragozaantigua/30949561710/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23884, 'El Pilar 1929', 'Foto: Miguel Mar‚îú¬°n Chivite. Vista del Pilar desde el puente de Piedra. A la izquierda, el palacio de Ayerbe. Fuente: Heraldo de Arag‚îú‚îÇn.', 1929, 1929, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65711600, -0.87552000, '0101000020E610000031CEDF844204ECBFD4D688601CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31641993175.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31641993175.webp', 'https://www.flickr.com/photos/zaragozaantigua/31641993175/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23891, 'Puente de Piedra y Pilar 1907', 'Postal editada por Fototipia Madriguera (Barcelona) en 1907, con una foto del puente de Piedra y el Pilar, cuya segunda torre aparece terminada y con el andamiaje sin retirar. En primer plano se aprecian vallas de obras de acondicionamiento del acceso al puente desde el Arrabal y del pretil de San L‚îú√≠zaro. Fuente: Heraldo de Arag‚îú‚îÇn.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65794900, -0.87504800, '0101000020E610000044C4CDA96400ECBFCCB73EAC37D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32462232375.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32462232375.webp', 'https://www.flickr.com/photos/zaragozaantigua/32462232375/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23899, 'Ovejas arrabaleras 1954', 'Curiosa imagen capturada desde la arboleda de Macanaz, junto a la ribera del Ebro donde unas ovejas se aventuran a abrevar de forma pl‚îú√≠cida, mientras el resto de la grey ramonea por el entorno, a la derecha y fuera de plano. Al otro lado, o margen derecha, vista del templo del Pilar con las obras de recrecimiento de las torres norte‚îú‚ñías (la de Santa Leonor a la izquierda, la de San Francisco de Borja a la derecha). Adem‚îú√≠s y a la izquierda, estructura de la nueva Casa Consistorial en la parte recayente al paseo de Echegaray a Caballero, menos adelantada que la esc‚îú¬Ænica fachada recayente a la plaza del Pilar. Esta postal forma parte de una experimental etapa transitoria entre las tradicionales postales en blanco y negro y las modernas en color, en la que los originales fotogr‚îú√≠ficos en blanco y negro se pintaban a mano y luego se imprim‚îú¬°an "en color". La denominaci‚îú‚îÇn de la editorial que distribuy‚îú‚îÇ esta imagen, P. Esper‚îú‚îÇn, hac‚îú¬°a referencia a uno de los pioneros de la fotograf‚îú¬°a en Espa‚îú‚ñía en el ‚îú‚ïëltimo tercio del siglo XIX: el franc‚îú¬Æs Alfred Esperon, espa‚îú‚ñíolizado Alfredo Esper‚îú‚îÇn, coet‚îú√≠neo de Jean Laurent.', 1954, 1954, 1954, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65837200, -0.87596800, '0101000020E6100000FDF50A0BEE07ECBF124DA08845D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/48859007223.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/48859007223.webp', 'https://www.flickr.com/photos/zaragozaantigua/48859007223/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23906, 'Puente de Piedra 1903', 'Imagen capturada a espaldas del cuartel de san L‚îú√≠zaro con el objetivo dirigido hacia el puente de Piedra jalonado por los postes de la reci‚îú¬Æn electrificada l‚îú¬°nea del tranv‚îú¬°a Arrabal. En el templo del Pilar progresan en su primera fase los andamios de obra del recrecimiento de la torre de N‚î¨¬¨ S‚î¨¬¨ del Pilar, proyectada por Jos‚îú¬Æ de Yarza Echenique con la colaboraci‚îú‚îÇn de Julio Bravo Folch y Ricardo Magdalena Tabuenca.', 1903, 1903, 1903, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65745900, -0.87526900, '0101000020E6100000E57B46223402ECBFFEBAD39D27D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51008667026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51008667026.webp', 'https://www.flickr.com/photos/zaragozaantigua/51008667026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24054, 'La Virgen al pozo 1975', 'Un grupo de submarinistas del Club Aragon‚îú¬Æs de Actividades Subacu‚îú√≠ticas, presidido por Manuel de la Figuera, sumergi‚îú‚îÇ en octubre de 1975 una estatua de plomo de la Virgen del Pilar en el pozo de San L‚îú√≠zaro, a 18 metros de profundidad. Eran Benito Poder‚îú‚îÇs, Alberto Marquet, Jos‚îú¬Æ Miguel Buera y Antonio Ram‚îú¬°rez. Para ello contaron con la colaboraci‚îú‚îÇn de miembros del Grupo de Espeleolog‚îú¬°a de Arag‚îú‚îÇn, que se descolgaron con la imagen hasta la embarcaci‚îú‚îÇn. Tambi‚îú¬Æn estuvo presente la secci‚îú‚îÇn juvenil de la Cruz Roja, para asistir en caso de accidente. Y el Regimiento de Pontoneros aport‚îú‚îÇ las lanchas. En esta ocasi‚îú‚îÇn, no hubo participaci‚îú‚îÇn del Cuerpo de Bomberos. Hubo bendici‚îú‚îÇn previa a cargo de un sacerdote flotante, momento que recoge la imagen, y numeroso p‚îú‚ïëblico congregado en el puente de Piedra. Al fondo, la torre de la Seo.', 1975, 1975, 1975, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65756800, -0.87469100, '0101000020E61000008D60E3FA77FDEBBFB4722F302BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31569827114.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31569827114.webp', 'https://www.flickr.com/photos/zaragozaantigua/31569827114/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24159, 'Zaragoza de gala 1919', '"Zaragoza de gala...". Ilustraci‚îú‚îÇn de A. D‚îú¬°az Dom‚îú¬°nguez para la portada del Heraldo de Arag‚îú‚îÇn del 21 de mayo de 1919, al d‚îú¬°a siguiente de la inauguraci‚îú‚îÇn de la Exposici‚îú‚îÇn Hispano-Francesa de Bellas Artes en la Lonja. A la derecha, el puente de Piedra. Fuente: Heraldo de Arag‚îú‚îÇn.', 1919, 1919, 1919, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32741619876.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32741619876.webp', 'https://www.flickr.com/photos/zaragozaantigua/32741619876/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24729, 'Puente de Piedra 1930', '"El Puente de Piedra y el Arrabal".', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65723400, -0.87536500, '0101000020E61000006C04E275FD02ECBFDEE8633E20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14682257087.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14682257087.webp', 'https://www.flickr.com/photos/zaragozaantigua/14682257087/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24731, 'Calle del Sobrarbe c.1900', 'Estudio Coyne/ DARA. Principios siglo XX. Imagen desde el principio de la calle Sobrarbe, con la iglesia parroquial de Altab‚îú√≠s a la derecha. Hemos volteado horizontalmente la imagen original, para que los edificios aparezcan en su sitio can‚îú‚îÇnico, como por ejemplo la f‚îú√≠brica de pan y luego el taller de carreter‚îú¬°a que a la izquierda se ubicaba en los bajos del inmueble del n‚î¨‚ïë 15 de la calle.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65858400, -0.87511200, '0101000020E6100000F3C98AE1EA00ECBF9DD5027B4CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14794207078.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14794207078.webp', 'https://www.flickr.com/photos/zaragozaantigua/14794207078/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24735, 'Puente de Piedra 1813', 'Bridge of the Ebro, Zaragoza. Eduard Hanke Locker, 1813. Publicado en Views in Spain, 1824. Desde la ribera derecha, Interesante vista del puente de Piedra que presenta el estado de la arcada inmediata a la margen derecha tras las reparaciones provisionales que mediante maderos permitieron reabrir al tr‚îú√≠nsito el puente tras ser destruida el 8 de julio tras la salida de la guarnici‚îú‚îÇn francesa. La restauraci‚îú‚îÇn final del puente se realiz‚îú‚îÇ a principios de 1814, justo para permitir que por ‚îú¬Æl transitara la comitiva del rey Fernando VII durante su visita a la ciudad en abril de ese a‚îú‚ñío. En la margen izquierda se destaca el convento de San L‚îú√≠zaro. Fuente: amable aportaci‚îú‚îÇn de Jos‚îú¬Æ Luis Cintora.', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15085000060.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15085000060.webp', 'https://www.flickr.com/photos/zaragozaantigua/15085000060/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24749, 'Puente de Piedra 1897', 'Imagen fotogr‚îú√≠fica convertida en estampa costumbrista t‚îú‚îÇpica. Centraremos el objetivo en el fondo, con el templo del Pilar de una sola torre, la de Santiago. En el Puente de Piedra, protegido por los cuatro p‚îú¬Ætreos leones, como hasta 1917. En el suelo, con se‚îú‚ñíales de los ra‚îú¬°les del reciente (fue inaugurado en marzo) ramal del tranv‚îú¬°a que conectaba la ciudad con el Arrabal, subdividido en dos l‚îú¬°neas: la primera, o directa, por la calle Sobrarbe (hacia la derecha). La segunda, o l‚îú¬°nea suplementaria, segu‚îú¬°a la carretera de Barcelona y terminaba en el patio de la estaci‚îú‚îÇn de ferrocarril del Norte (hacia donde se dirige el paisano). Y en la vivienda de la derecha, que formaba parte de la calle Sobrarbe, justo al lado de las v‚îú¬°as que por debajo permit‚îú¬°an circular al ferrocarril hacia el puente de la Almozara. Fuente visual: "La Revista Moderna", Madrid.', 1897, 1897, 1897, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65822000, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15838488112.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15838488112.webp', 'https://www.flickr.com/photos/zaragozaantigua/15838488112/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24774, 'Calle Sobrarbe 1964', 'Rururbana imagen durante la celebraci‚îú‚îÇn de San Isidro Labrador por la franquista "Hermandad Sindical de Labradores y Ganaderos", que aprovechaba su nulo gasto energ‚îú¬Ætico, reivindicativo y movilizador, durante el resto del a‚îú‚ñío, para concentrar su fogosidad en esta fecha. Ese a‚îú‚ñío, adem‚îú√≠s, a‚îú‚ñíad‚îú¬°a a la celebraci‚îú‚îÇn la oficial campa‚îú‚ñía de los "25 a‚îú‚ñíos de Paz", como ilustra la pancarta de la carroza mecanizada de la imagen, llegada de Villamayor, en su alegre desfilar por la calle de Sobrarbe, hacia el Puente de Piedra, como parte de la festiva caravana agr‚îú¬°cola-nacionalista. Al fondo, las torres de la iglesia parroquial de Nuestra Se‚îú‚ñíora de Altab‚îú√≠s. Fuente visual: Gerardo Sancho Ramo, Archivo P‚îú‚ïëblico Municipal.', 1964, 1964, 1964, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65859100, -0.87447400, '0101000020E61000004679E6E5B0FBEBBF5038BBB54CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24558564680.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24558564680.webp', 'https://www.flickr.com/photos/zaragozaantigua/24558564680/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24787, 'Puente de Piedra 1968', 'Imagen de la unidad n‚î¨‚ïë 12 de la l‚îú¬°nea de trolebuses "G‚îú√≠llego" pasando por el puente de Piedra, en su ruta hacia la terminal de la calle de la Ver‚îú‚îÇnica. Se trata de uno de los "BUT" de 1 piso venidos de Londres, a los que deber‚îú¬°an haber acompa‚îú‚ñíado algunos "BUT" de 2 pisos, pero la baja altura del puente del ferrocarril que cruzaba la avenida de Catalu‚îú‚ñía, desaconsej‚îú‚îÇ su uso en esta l‚îú¬°nea. A la izquierda, el recient‚îú¬°simo gran bloque de viviendas de los n‚îú‚ïëmeros 2, 4 y 6 de la calle Sixto Celorrio. Al fondo, la iglesia parroquial de Altab‚îú√≠s en la calle de Sobrarbe, y el convento de Terciarias Franciscanas de Altab‚îú√≠s. A la derecha, la plazuela arbolada inmediata al cuartel de San L‚îú√≠zaro. En el firme, trazado de las v‚îú¬°as de la l‚îú¬°nea 10 "Arrabal-Academia" del tranv‚îú¬°a. Fuente visual: Foto Bernard Harrison, a trav‚îú¬Æs de www.forotrenes.com/', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65746800, -0.87519800, '0101000020E610000097C9703C9F01ECBF511553E927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30484724153.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30484724153.webp', 'https://www.flickr.com/photos/zaragozaantigua/30484724153/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21092, 'Monasterio de Santa Fe 1871', '"Ruinas de Santa Fe". Dibujo de Santiago Ram‚îú‚îÇn y Cajal, 2 de octubre de 1871. Representa los restos del monasterio cisterciense de Santa Mar‚îú¬°a en Santa Fe de Huerva, enclave perteneciente al municipio de Zaragoza, adscrito al distrito de Casablanca. A la derecha, vista parcial de la torre de la iglesia barroca.', 1871, 1871, 1871, 'Siglo XIX', NULL, 41.57696100, -0.95160400, '0101000020E6100000E3C4573B8A73EEBFA208A9DBD9C94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53395684049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53395684049.webp', 'https://www.flickr.com/photos/zaragozaantigua/53395684049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24806, '1968 Arrabal', 'Imagen centrada en la unidad n‚î¨‚ïë 161 de la tranviaria serie "Topolinos", en servicio en la l‚îú¬°nea 4 "Arrabal", regresando a la terminal de la plaza de la Seo. La captura se ha realizado en el puente de Piedra, con el tel‚îú‚îÇn de fondo de algunas edificaciones referenciales de la margen izquierda, como la iglesia de Altab‚îú√≠s, el cuartel de San L‚îú√≠zaro, y el nov‚îú¬°simo bloque del 2-4-6 de la calle Sixto Celorrio. Tras el tranv‚îú¬°a, un troleb‚îú‚ïës, bien de la l‚îú¬°nea "G‚îú√≠llego", bien de la "Barrio Jes‚îú‚ïës", hacia su terminal en la calle de la Ver‚îú‚îÇnica. Tras la clausura de la l‚îú¬°nea "Arrabal" a finales de 1971, este "Topolino" fue desguazado. Fuente visual: foto Bernard Harrison, en www.flickr.com/photos/30937/19043809034/', 1968, 1968, 1968, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65778100, -0.87503100, '0101000020E6100000C18EFF024100ECBF1077F52A32D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/33752800645.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/33752800645.webp', 'https://www.flickr.com/photos/zaragozaantigua/33752800645/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24826, 'Margen izquierda c.1931', 'Imagen capturada desde la altura de la torre de la Seo y orientada hacia la margen izquierda o Arrabal. En primer t‚îú¬Ærmino, patio del Seminario metropolitano y Universidad Pontificia anexo al Palacio Arzobispal. Centra la escena el puente de Piedra y el r‚îú¬°o Ebro. En la ribera norte, la calle del Sobrarbe anuncia la carretera de Zaragoza a Huesca junto al cauce al aire de la acequia de Juslibol, y hacia la derecha la avenida de Catalu‚îú‚ñía, con el cuartel de San L‚îú√≠zaro, la estaci‚îú‚îÇn del Arrabal y el gran pol‚îú¬°gono industrial conformado por Maquinista y Fundiciones del Ebro, S.A., la Nueva Harinera y la Harinera del Arrabal. Hacia la izquierda, el camino de Ranillas y la calle de Sixto Celorrio que conduce al parque de Ibort.', 1931, 1931, 1931, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65737400, -0.87526900, '0101000020E6100000E57B46223402ECBFCF9ECBD424D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50708983541.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50708983541.webp', 'https://www.flickr.com/photos/zaragozaantigua/50708983541/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24827, 'Comparsa Gigantes 1978', 'Imagen centrada en la comparsa de Gigantes durante las Fiestas del Pilar que, proveniente del puente de Piedra, se encamina en descenso hacia la calle de Sixto Celorrio. Con el incomparable fondo del templo del Pilar desfilan con su at‚îú√≠vica parsimonia los personajes del Rey, la Reina, Don Quijote, Dulcinea, Chino, Negra, Gast‚îú‚îÇn de Bearn y la Bearnesa. Estos fueron los ‚îú‚ïëltimos "pilares" del antiguo r‚îú¬Ægimen, cuando la ‚îú‚ïëltima corporaci‚îú‚îÇn heredada del franquismo mont‚îú‚îÇ una "programaci‚îú‚îÇn" centrada en la ofrenda de flores a la Virgen del Pilar y el clasista ceremonial de la "reina de las fiestas" (Montserrat Genzor) elegida entre las familiares elites que gobiernan esta ciudad. Unas paralelas "Fiestas Populares" intentaron insuflar aires nuevos con m‚îú√≠s ilusi‚îú‚îÇn que medios. Tras las elecciones municipales de 1979, este panorama cambi‚îú‚îÇ de forma importante.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65822000, -0.87492500, '0101000020E6100000567DAEB662FFEBBF5CC98E8D40D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50862393197.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50862393197.webp', 'https://www.flickr.com/photos/zaragozaantigua/50862393197/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24869, 'Vuelo sobre el Ebro 1911', 'Imagen capturada desde el puente de Hierro y centrada en el tradicional fondo esc‚îú¬Ænico que sobre el r‚îú¬°o Ebro formaban el puente de Piedra y la monumental fachada fluvial de la margen derecha, desde el Seminario metropolitano hasta el templo del Pilar. El singular elemento que diferencia esta fotograf‚îú¬°a de otras similares es el monoplano Bl‚îú¬Æriot pilotado por el franc‚îú¬Æs Joseph Gaget que en la parte superior derecha sobrevuela el r‚îú¬°o Ebro hacia el oriente durante la disputa con el tambi‚îú¬Æn franc‚îú¬Æs Andr‚îú¬Æ Frey de la "Copa Zaragoza" disputada el 27 de abril, tras la finalizaci‚îú‚îÇn de la exitosa "II Semana de la Aviaci‚îú‚îÇn" celebrada entre el 17 y el 25 de abril de 1911. Realizados sus respectivos vuelos y regresados ambos al aer‚îú‚îÇdromo de Valdespartera, el jurado formado por el marqu‚îú¬Æs de Arlanza, el bar‚îú‚îÇn de Benasque y los se‚îú‚ñíores Juncosa, Escoriaza, Valenzuela, La Rosa y Macipe, decidi‚îú‚îÇ que la copa donada por el Sindicato de Iniciativas de Zaragoza recayera en Joseph Gaget.', 1911, 1911, 1911, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65680100, -0.87457100, '0101000020E6100000E4F560527CFCEBBF747D1F0E12D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51688359798.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51688359798.webp', 'https://www.flickr.com/photos/zaragozaantigua/51688359798/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24889, 'Monumento a Santo Dominguito de Val 1958', 'Obra del escultor Antonio Bueno e inaugurado en 1951 junto al cuartel de San L‚îú√≠zaro (en la foto, detr‚îú√≠s), fue retirado en los a‚îú‚ñíos 80 cuando el lugar se transform‚îú‚îÇ en el Balc‚îú‚îÇn de San L‚îú√≠zaro. Foto de diciembre de 1958. Fuente: elbalcondesanlazaro.blogspot.com.es/2013/12/monumento-san...', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65808700, -0.87458400, '0101000020E61000000C5BB39597FCEBBF1D76DF313CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15022737919.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15022737919.webp', 'https://www.flickr.com/photos/zaragozaantigua/15022737919/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25073, 'Monumento a Santo Dominguito de Val 1976', 'Domingo ("Dominguito") es un legendario monaguillo de la catedral de San Salvador convertido por el oficial antisemitismo medieval de la iglesia cat‚îú‚îÇlica en "Santo Dominguito de Val". La atroz f‚îú√≠bula que justific‚îú‚îÇ su canonizaci‚îú‚îÇn es una suma de monstruosidades de tal calibre, que la propia iglesia cat‚îú‚îÇlica, tras el Concilio Vaticano II, convino en suprimir su culto, aunque sigue siendo practicado por el catolicismo ultra. En la imagen, monumento que el nacional catolicismo local dedic‚îú‚îÇ a esta m‚îú‚îÇrbida historia, casi 700 a‚îú‚ñíos despu‚îú¬Æs de su supuesto acontecimiento. Es obra de Antonio Bueno, y hab‚îú¬°a sido inaugurado en 1951 en una glorieta entre el puente de Piedra y el cuartel de San L‚îú√≠zaro (en la imagen, al fondo). Justo detr‚îú√≠s hab‚îú¬°a una fuente de agua potable, tal vez lo ‚îú‚ïënico sano del conjunto. All‚îú¬° permaneci‚îú‚îÇ hasta que a mediados de los a‚îú‚ñíos 80 la plaza donde se ubicaba fue remodelada, sin que tras esa obra este monumento fuera repuesto.', 1976, 1976, 1976, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65808700, -0.87458400, '0101000020E61000000C5BB39597FCEBBF1D76DF313CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18653379440.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18653379440.webp', 'https://www.flickr.com/photos/zaragozaantigua/18653379440/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21240, 'Conservas Marraco 1908', 'F‚îú√≠brica de conservas vegetales de Manuel Marraco, luego Marraco Hermanos, en el barrio de Monzalbarba de Zaragoza, 1908. Ubicada cerca de la estaci‚îú‚îÇn ferroviaria Utebo-Monzalbarba, contaba con cultivos propios. Empez‚îú‚îÇ su actividad en 1895. Entre sus especialidades, guisantes al estilo franc‚îú¬Æs y pur‚îú¬Æ de tomate concentrado por evaporaci‚îú‚îÇn al vac‚îú¬°o. Fuente: M‚î¨¬¨ Pilar Biel Ib‚îú√≠‚îú‚ñíez, Zaragoza y la industrializaci‚îú‚îÇn: la arquitectura industrial 1875-1926, IFC, 2004.', 1908, 1908, 1908, 'Anos 1900', NULL, 41.70046300, -0.98148100, '0101000020E6100000ECA694D74A68EFBF6E8786C5A8D94440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19638715286.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19638715286.webp', 'https://www.flickr.com/photos/zaragozaantigua/19638715286/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25109, 'The Stone Bridge 1891', '"The stone bridge at Saragossa. The destructive floods in Spain." Dibujo del puente de piedra, como parte de la portada del "The Illustrated London News", de setiembre de 1891, informando de unas "desastrosas" y "destructivas" inundaciones que hab‚îú¬°an tenido lugar en Espa‚îú‚ñía. Sucede que este dibujo es una copia literal de una fotograf‚îú¬°a tomada un par de a‚îú‚ñíos antes por J. L‚îú¬Ævy et Cie, y no precisamente en un momento en que el r‚îú¬°o se hubiera salido de madre: el antiguo azud espumea. Fuente visual: Fondo Documental Hist‚îú‚îÇrico de las Cortes de Arag‚îú‚îÇn.', 1891, 1891, 1891, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65769900, -0.87507600, '0101000020E6100000C07630629F00ECBF53CE177B2FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877110002.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877110002.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877110002/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25135, 'Puente de Piedra 1890', 'Vista del Puente de Piedra y el Pilar. Cromo de la colecci‚îú‚îÇn del "Aut‚îú¬Æntico extracto de carne Liebig", publicado en Par‚îú¬°s en 1899. La imagen del Pilar es anterior a la de la finalizaci‚îú‚îÇn del remate de la torre de Santiago del Pilar.', 1890, 1890, 1890, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19149319049.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19149319049.webp', 'https://www.flickr.com/photos/zaragozaantigua/19149319049/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25142, 'El Pilar c.1910', 'Cartel publicitario a colores, sobre chapa litografiada, y en relieve, realizado por "Litograf‚îú¬°a La Art‚îú¬°stica, Coru‚îú‚ñía" para la reci‚îú¬Æn inaugurada f‚îú√≠brica de galletas "Patria". El dibujo est‚îú√≠ situado en una de las localizaciones est‚îú√≠ndar de la ciudad: el puente de Piedra sobre el r‚îú¬°o Ebro, con la catedral de El Pilar como fondo de imagen, ya recrecida su segunda torre, la de "N‚î¨¬¨ S‚î¨¬¨ del Pilar". Sobre el puente, el "cami‚îú‚îÇn-autom‚îú‚îÇvil" para tr‚îú√≠fico de mercanc‚îú¬°as de la empresa anunciante, coincide con un par de ind‚îú¬°genas, caracterizados con t‚îú‚îÇpicos ropajes folcl‚îú‚îÇricos, en dulce situaci‚îú‚îÇn, pues ella le ofrece un irresistible bizcocho troquelado de la met‚îú√≠lica caja que guarda bajo el brazo. ‚îú√´l, entrecierra los ojos ante la prometedora circunstancia, y se aproxima sumiso, d‚îú‚îÇcil. Fuente: Colecci‚îú‚îÇn Mar‚îú¬°a Tausiet.', 1910, 1910, 1910, 'Anos 10', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24136224013.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24136224013.webp', 'https://www.flickr.com/photos/zaragozaantigua/24136224013/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25148, 'Puente de Piedra 1813', 'Bridge of the Ebro, Zaragoza. Dibujo original de Eduard Hanke Locker, publicado en Londres dentro de la obra "Views in Spain, 1824", por Rodwell and Martin, e impreso por C. Hullmandel. Al fondo, el convento mercedario de San L‚îú√≠zaro, y ruinas provocadas por la explosi‚îú‚îÇn de la ‚îú‚ïëltima arcada del puente de Piedra, provocada por las tropas francesas en retirada. Destacan los provisionales apa‚îú‚ñíos en madera para permitir el tr‚îú√≠nsito por el puente. Inmediata, la antigua iglesia parroquial de Altab‚îú√≠s. Fuente: www.cortesaragon.es/', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65746800, -0.87519800, '0101000020E610000097C9703C9F01ECBF511553E927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30598949751.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30598949751.webp', 'https://www.flickr.com/photos/zaragozaantigua/30598949751/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25192, 'Puente Colgante Ebro 1838', 'El penoso estado del puente de Piedra llev‚îú‚îÇ en 1838 al Ayuntamiento a convocar un concurso para construir uno nuevo que sustituyera al "viejo", que ser‚îú¬°a derribado. La imagen representa uno de los proyectos presentados, firmado por Federico Ang‚îú√≠n y Juan de la Vega, que imitando modelos franceses, propone un puente colgante con dos tramos y sostenido por alambres amarrados en las m‚îú√≠rgenes. Al estar previsto el derribo del puente de Piedra, a‚îú‚ñíad‚îú¬°an al proyecto cuatro pedestales y dos pilares monumentales con decoraciones alusivas al hero‚îú¬°smo de los Sitios, todo para dar realce esc‚îú¬Ænico a la que ser‚îú¬°a principal entrada a la ciudad desde el otro lado del Ebro. Nuevos leones sobre los pedestales, m‚îú√≠s grandes, pero igual de sedentes, contemplar‚îú¬°an el tr‚îú√≠nsito del Ebro. La ruina econ‚îú‚îÇmica municipal aparc‚îú‚îÇ al resoluci‚îú‚îÇn del concurso, y los proyectos presentados quedaron archivados. El viejo puente de Piedra supervivi‚îú‚îÇ. Fuente visual: AMZ. Fuente textual: M‚î¨¬¨ Pilar Biel, "Los puentes met‚îú√≠licos de carretera sobre el Ebro en la provincia de Zaragoza", Artigrama, 2000.', 1838, 1838, 1838, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65735400, -0.87596600, '0101000020E6100000D00D4DD9E907ECBF88F2052D24D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19561141906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19561141906.webp', 'https://www.flickr.com/photos/zaragozaantigua/19561141906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25409, 'Puerta del ‚îú√ºngel 1866', 'Foto: Mariano J‚îú‚ïëdez. Puerta del ‚îú√ºngel, puente de Piedra y bas‚îú¬°lica del Pilar. Fuente: Antiguas puertas de Zaragoza, IFC, 2013.', 1866, 1866, 1866, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65739400, -0.87494000, '0101000020E6100000ACCABE2B82FFEBBF164B917C25D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14978759632.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14978759632.webp', 'https://www.flickr.com/photos/zaragozaantigua/14978759632/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25410, 'Voladura del puente de Piedra 1813', 'Voladura en incendio del puente de Piedra de Zaragoza la noche del 9 de julio de 1813, al ser abandonada por los franceses. Aguafuerte an‚îú‚îÇnimo, atribuido a M. Latassa. Terminaban as‚îú¬° cuatro a‚îú‚ñíos de gobierno franc‚îú¬Æs en la ciudad. Seg‚îú‚ïën la Gu‚îú¬°a de Zaragoza de 1860, √î√á¬£Durante la permanencia de los franceses en Zaragoza, se mejor‚îú‚îÇ la ciudad y sus afueras; proyect‚îú√≠ndose vastas obras de p‚îú‚ïëblica utilidad, que los acontecimientos de la guerra impidieron verificar. Propagandistas y creadores, dejaron en Zaragoza huellas de su paso; y, como en todas partes, semillas de otras ideas que en su d‚îú¬°a hab‚îú¬°an de germinar. Aquellas semillas brotaron a principios del a‚îú‚ñío 1820, proclam‚îú√≠ndose en Zaragoza la Constituci‚îú‚îÇn√î√á√ò. M‚îú√≠s informaci‚îú‚îÇn: tausiet.blogspot.com.es/2016/01/contrasitios.html', 1813, 1813, 1813, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65715400, -0.87538600, '0101000020E61000004A0A2C802903ECBFC1374D9F1DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15019494481.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15019494481.webp', 'https://www.flickr.com/photos/zaragozaantigua/15019494481/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25411, 'Puente de Piedra 1960', 'Archivo Municipal. Gerardo Sancho Ramo. 1960. Imagen de uno de los tajamares del puente de Piedra cuando, aprovechando el bajo caudal del est‚îú¬°o, eran aprovechados como lugar de refresco de pies. Esta mirada cenital permite tambi‚îú¬Æn apreciar las met‚îú√≠licas grapas con que se reforzaba la uni‚îú‚îÇn entre los bloques de piedra de la base del puente.', 1960, 1960, 1960, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65781100, -0.87480700, '0101000020E6100000DBFAE93F6BFEEBBF7BF99D2633D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15162728973.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15162728973.webp', 'https://www.flickr.com/photos/zaragozaantigua/15162728973/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23773, 'Empresarium 2006', 'Recreaci‚îú‚îÇn del pol‚îú¬°gono industrial Empresarium de La Cartuja Baja (350 hect‚îú√≠reas), inaugurado en 2006. Este complejo fue ideado en 1990, cuando Tudor se traslad‚îú‚îÇ a la zona. Se ubica entre el barranco de las Casetas (izquierda) y el Canal Imperial de Arag‚îú‚îÇn (derecha). Est‚îú√≠ atravesado por la l‚îú¬°nea ferroviaria a Barcelona. Al fondo a la derecha se halla el Parque Tecnol‚îú‚îÇgico de Reciclado L‚îú‚îÇpez Soriano (850 hect‚îú√≠reas), ya en el distrito de Torrero-La Paz. La imagen promocional, colmatada de naves industriales y con amplias zonas verdes, dista del estado real una d‚îú¬Æcada despu‚îú¬Æs. Fuente visual: Heraldo de Arag‚îú‚îÇn.', 2006, 2006, 2006, 'Siglo XXI', NULL, 41.58959600, -0.81776000, '0101000020E61000004243FF04172BEABF1CEDB8E177CB4440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31699829484.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31699829484.webp', 'https://www.flickr.com/photos/zaragozaantigua/31699829484/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25413, 'Puente de Piedra 1955', 'Por el puente de Piedra y entre poco tr‚îú√≠fico circula un troleb‚îú‚ïës de la l‚îú¬°nea Barrio Jes‚îú‚ïës que hab‚îú¬°a sustituido recientemente a la hom‚îú‚îÇnima l‚îú¬°nea tranviaria. La calle del Sobrarbe, tras el puente que salva la trinchera del enlace del ferrocarril, asciende por el barrio del Arrabal pasando junto al convento de Santa Isabel, el grupo escolar C‚îú√≠ndido Domingo y la iglesia de Altab‚îú√≠s, y poco despu‚îú¬Æs del acceso al patio de carros de la estaci‚îú‚îÇn del Norte o Arrabal, se convierte ya en la carretera de Huesca. Al fondo se perfilan las chimeneas de la f‚îú√≠brica de la Uni‚îú‚îÇn Alcoholera Espa‚îú‚ñíola, y en las alturas del Cascajo se eleva el moderno Dispensario Central Antituberculoso, con sus cinco plantas y cuatrocientas camas llenas de pacientes como consecuencia de la endemia tuberculosa de la ‚îú¬Æpoca. Fuente Visual: Editorial Arribas, AMZ', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15174915899.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15174915899.webp', 'https://www.flickr.com/photos/zaragozaantigua/15174915899/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25420, 'Puente de Piedra 1444', '"Puente de Piedra, Zaragoza (the bridge on the left)" Charles Holroyd, 1906 "At left, view of the Puente de Piedra; at right, Nuestra Se‚îú‚ñíora del Pilar, Zaragoza". Aguafuerte de muy elevada enso‚îú‚ñíaci‚îú‚îÇn rom‚îú√≠ntica, imaginando el aspecto de la ciudad en alg‚îú‚ïën momento de su baja edad media, con el puente de Piedra sobre el r‚îú¬°o Ebro, y una murallas que causaban pavor a los potenciales enemigos. Por m‚îú√≠s que lo buscamos, no encontramos traza del Pilar (ni de Santa Mar‚îú¬°a la Mayor, su antecedente): nos lo impide la arboleda. Fuente visual: www.britishmuseum.org/', 1444, 1444, 1444, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/17504263688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/17504263688.webp', 'https://www.flickr.com/photos/zaragozaantigua/17504263688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25427, 'Puente de Piedra y el Pilar 1962', 'Puente de Piedra, con el Pilar al fondo en julio de 1962, a‚îú‚ñío siguiente de terminar de colocarle una torre en cada esquina. Fuente: www.flickr.com/photos/122511173@N05/13699516045', 1962, 1962, 1962, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20657984246.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20657984246.webp', 'https://www.flickr.com/photos/zaragozaantigua/20657984246/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25428, 'Puente de Piedra 1958', 'Tranv‚îú¬°a de la l‚îú¬°nea 10 "Academia" a su paso por el puente de Piedra de Zaragoza. Al fondo, la Lonja y el Pilar. Fuente: elbalcondesanlazaro.blogspot.com', 1958, 1958, 1958, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65694900, -0.87549300, '0101000020E6100000CB0F5CE50904ECBFE811A3E716D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20901246296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20901246296.webp', 'https://www.flickr.com/photos/zaragozaantigua/20901246296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25429, 'Puente de Piedra 1965', 'Foto: Fernando Llaurad‚îú‚îÇ, 10-4-1965. Un troleb‚îú‚ïës BUT cruza el puente de Piedra de Zaragoza. Al fondo a la izquierda, la arboleda de Macanaz. Fuente: www.facebook.com/photo.php?fbid=409282679236402&set=p...', 1965, 1965, 1965, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65665500, -0.87583900, '0101000020E610000088F6B182DF06ECBFA0E062450DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20904827633.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20904827633.webp', 'https://www.flickr.com/photos/zaragozaantigua/20904827633/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25441, 'Puente de Piedra 1877', 'Interesante imagen del puente de Piedra y el r‚îú¬°o Ebro capturadas desde la margen derecha, desde cierta altura. Inmediato, silueteado por el templo del Pilar, el paseo del Ebro aparece bien despejado, antes de plantaciones y tendido tranviario. El puente de Piedra sigue siendo el ‚îú‚ïënico puente de tr‚îú√≠nsito y conexi‚îú‚îÇn en esta parte de la ciudad. En el Arrabal, destaca al fondo la desmochada torre del antiguo convento franciscano de Jes‚îú‚ïës. A su derecha, restos del antiguo convento mercedario de San L‚îú√≠zaro, ya como parte del recinto militarizado y convertido hac‚îú¬°a poco en cuartel del ej‚îú¬Ærcito. Despunta, incluso, algo m‚îú√≠s hacia la derecha, el ilustrado molino de harina que antes estuviera junto al puente de Piedra. En el puente, en temporada de aguas bajas, visual del efecto producido por los restos del antiguo azud. Fuente visual: Jean Laurent & C‚îú¬°a (AHPZ-DARA)', 1877, 1877, 1877, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65742400, -0.87530300, '0101000020E6100000EBE6E26F7B02ECBF81CD397826D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/28303352100.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/28303352100.webp', 'https://www.flickr.com/photos/zaragozaantigua/28303352100/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25448, 'Puente de Piedra 1967', 'Imagen centrada en el obraje abierto en el puente de Piedra, capturada en direcci‚îú‚îÇn hacia la margen izquierda. Al fondo, y a la izquierda, el ascendente esqueleto que vertebra el nuevo gran bloque de viviendas de los n‚îú‚ïëmeros 2, 4 y 6 de la calle Sixto Celorrio. Al fondo, las pareadas cupulillas de la iglesia parroquial de Altab‚îú√≠s en la calle de Sobrarbe. En el firme, flanqueando la zanja, trazado de las v‚îú¬°as de la tranviaria l‚îú¬°nea 10 "Arrabal-Academia", una de cuyas unidades ha pasado recientemente en direcci‚îú‚îÇn a la castrense academia. Parece ser que la transitoria interrupci‚îú‚îÇn de tr‚îú√≠fico rodado, en esta ocasi‚îú‚îÇn, no supuso el colapso social, econ‚îú‚îÇmico y cultural de la margen izquierda de la ciudad. Fuente visual: foto Gerardo Sancho Ramo, en AMZ.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32596430234.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32596430234.webp', 'https://www.flickr.com/photos/zaragozaantigua/32596430234/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25449, 'Fuegos artificales 1952', 'Anochece en esta escena tomada desde las traseras del cuartel de San L‚îú√≠zaro junto a la margen izquierda del r‚îú¬°o Ebro, y centrada en el puente de Piedra lleno de paisanos observando los fuegos artificiales lanzados desde la arboleda de Macanaz. A la izquierda, la estructura del nuevo palacio municipal y el templo del Pilar en el que se destacan las luminosas jaculatorias que coronan sus dos torres y las c‚îú‚ïëpulas mayores y menores. Emerge en obras el esqueleto de la nueva torre de Santa Leonor, mientras que la de San Francisco de Borja a‚îú‚ïën no ha sido iniciada. Al fondo, entre las arcadas del puente de Piedra, la pasarela de Macanaz tambi‚îú¬Æn repleta de observantes de las ruidosas luminarias noctunas. Fuente visual: AMZ', 1952, 1952, 1952, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32978126618.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32978126618.webp', 'https://www.flickr.com/photos/zaragozaantigua/32978126618/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25451, 'Puente de Piedra 1882', 'Dibujo al natural de Juan Comba y dise‚îú‚ñío de Bernardo Rico que ilustra el paso del puente de Piedra por la castrense comitiva que a lomos de caballo acompa‚îú‚ñíaba al rey Alfonso XII en direcci‚îú‚îÇn al campo de San Gregorio a unas maniobras y evoluciones militares incluidas en los festejos por el inicio de las obras del ferrocarril de Canfranc. La escena ha sido capturada desde la margen izquierda del r‚îú¬°o Ebro, con el tel‚îú‚îÇn de fondo de la Seo, el palacio arzobispal (donde se hospedaba el rey), el Seminario Conciliar, la calle de la Lonja, y la Casa Ayuntamiento y Lonja. Sobre el puente, postes del tendido y farolas el‚îú¬Æctricas. Fuente visual: La Ilustraci‚îú‚îÇn espa‚îú‚ñíola y americana (1882)', 1882, 1882, 1882, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34384976430.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34384976430.webp', 'https://www.flickr.com/photos/zaragozaantigua/34384976430/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25455, 'Bajo el puente de Piedra c.1950', 'Escena capturada bajo la cuarta arcada del puente de Piedra (originalmente, la quinta), y centrada en el templo del Pilar poco antes del inicio del recrecimiento de las torres ribere‚îú‚ñías. En primer t‚îú¬Ærmino, la p‚îú¬Ætrea solera iluminada por la solana. A la izquierda, vista residual del esqueleto del "palacio municipal", o nuevo ayuntamiento de la ciudad. Sobre el canicular cauce del r‚îú¬°o Ebro, un par de barcas navegan sin necesidad de dragado, y en la orilla algunas personas buscan el refresco junto al agua. Fuente visual: www.todocoleccion.net/', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65712700, -0.87540000, '0101000020E610000088635DDC4603ECBFC828CFBC1CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/46092985534.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/46092985534.webp', 'https://www.flickr.com/photos/zaragozaantigua/46092985534/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25460, 'Vista c.1885', 'Vista del puente de Piedra sobre un r‚îú¬°o Ebro con apreciable caudal de agua, centrada con el fondo del templo del Pilar caracterizado por su notable conjunto de c‚îú‚ïëpulas entre las que despunta levemente la inacabada torre de Santiago. A la izquierda, la Torre Nueva desmochada de su remate barroco en forma de triple chapitel, emerge sobre la nueva gran casa del marqu‚îú¬Æs de Ayerbe esquinera con la calle de Alfonso I que albergaba el Pasaje del Comercio y de la Industria, y de la veterana casa del mismo marqu‚îú¬Æs ubicada en la calle del Pilar. Junto al puente, el edificio de la Casa Consistorial y la Lonja.', 1885, 1885, 1885, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65686500, -0.87465700, '0101000020E610000088F546AD30FDEBBF8B71FE2614D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51398454762.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51398454762.webp', 'https://www.flickr.com/photos/zaragozaantigua/51398454762/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25461, 'Vista desde Altabas c.1874', 'Tercera de las vistas capturadas por Jean Laurent y C‚îú¬°a. que forma parte del extraordinario tr‚îú¬°ptico titulado "Vista general desde Altabas". Esta toma se centra en el puente de Piedra y la fachada de la ciudad al Ebro desde las Casas Consistoriales hasta San Juan de los Panetes. La gran c‚îú‚ïëpula central del Pilar y las c‚îú‚ïëpulas del Coro aparecen ya terminadas.', 1874, 1874, 1874, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65713800, -0.87545100, '0101000020E61000001004C8D0B103ECBFBC7A15191DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/54141492733.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/54141492733.webp', 'https://www.flickr.com/photos/zaragozaantigua/54141492733/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25532, 'El Pilar 1908', 'Foto Santiago Ram‚îú‚îÇn y Cajal, Diputaci‚îú‚îÇn de Zaragoza, 1908. Toma desde el Puente de Piedra del r‚îú¬°o Ebro y el Pilar. En primer plano, a la izquierda, la Cruz en Memoria de Basilio Boggiero, Santiago Sas y el Bar‚îú‚îÇn de Warsage, levantada seg‚îú‚ïën dise‚îú‚ñío de Ricardo Magdalena en 1908, el mismo a‚îú‚ñío en el que el premio Nobel realiz‚îú‚îÇ la fotograf‚îú¬°a. Fuente: web.dpz.es/arscatalogi.es/', 1908, 1908, 1908, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65761400, -0.87543400, '0101000020E61000008ECEF9298E03ECBF25B20FB22CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15713909180.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15713909180.webp', 'https://www.flickr.com/photos/zaragozaantigua/15713909180/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25535, 'Vista 1959', 'Desde los nuevos bloques de viviendas de la calle de Cecilio Navarro junto al puente de Hierro y en altura, una buena vista panor‚îú√≠mica y en detalle de las riberas del Ebro, tanto de la derecha, donde progresa significativamente la obra del nuevo ayuntamiento y el recrecimiento de las dos nuevas torres ribere‚îú‚ñías del Pilar, como de la margen izquierda, donde destaca el cuartel de San L‚îú√≠zaro, el monumento a Santo Dominguito de Val, la v‚îú¬°a del enlace ferroviario entre las estaciones del Norte y de Delicias, la arboleda de Macanaz y el barrio de la Ortilla. Sobre el Ebro, el puente de Piedra, la pasarela peatonal y al fondo el puente del ferrocarril.', 1959, 1959, 1959, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16095665676.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16095665676.webp', 'https://www.flickr.com/photos/zaragozaantigua/16095665676/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25542, 'Puente de Piedra 1908', 'Vista del puente de Piedra y el Arrabal de Zaragoza en una fotograf‚îú¬°a de Anselmo Coyne de 1908, editada como postal en Madrid por Casta‚îú‚ñíeira y ‚îú√ºlvarez en 1909. Fuente: Heraldo de Arag‚îú‚îÇn.', 1908, 1908, 1908, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65723200, -0.87536700, '0101000020E61000009AEC9FA70103ECBF3DF19C2D20D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20523149310.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20523149310.webp', 'https://www.flickr.com/photos/zaragozaantigua/20523149310/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25548, 'Vista Arrabal 1934', 'Foto: Tom‚îú√≠s Mora. Vista del Arrabal desde la torre de Santiago del Pilar. Fuente: www.facebook.com/photo.php?fbid=1198110743550375&set=...', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65909100, -0.87536700, '0101000020E61000009AEC9FA70103ECBF410B09185DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23584730783.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23584730783.webp', 'https://www.flickr.com/photos/zaragozaantigua/23584730783/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25553, 'Puente de Piedra 1907', 'Foto: Lucien Roy. Vista parcial del puente de Piedra, con la torre de la Seo al fondo. Fuente: Minist‚îú¬øre de la Culture (France) - M‚îú¬Ædiath‚îú¬øque de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65683200, -0.87555900, '0101000020E6100000A8FDD64E9404ECBFAF7B2B1213D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24591836583.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24591836583.webp', 'https://www.flickr.com/photos/zaragozaantigua/24591836583/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25557, 'Puente de Piedra 1907', 'Foto: Lucien Roy. Vista del puente de Piedra desde la margen derecha del Ebro, durante las obras de restauraci‚îú‚îÇn de 1907. Fuente: Minist‚îú¬øre de la Culture (France) - M‚îú¬Ædiath‚îú¬øque de l''architecture et du patrimoine.', 1907, 1907, 1907, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65683200, -0.87555900, '0101000020E6100000A8FDD64E9404ECBFAF7B2B1213D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25125199221.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25125199221.webp', 'https://www.flickr.com/photos/zaragozaantigua/25125199221/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25563, 'Puente de Piedra 1981', 'En mayo de 1981 se procedi‚îú‚îÇ a la retirada del cauce del Ebro del autob‚îú‚ïës que hab‚îú¬°a ca‚îú¬°do all‚îú¬° en diciembre de 1971, eso s‚îú¬°, bastante demediado 10 a‚îú‚ñíos despu‚îú¬Æs. La mitolog‚îú¬°a zaragozana se aliment‚îú‚îÇ de aquel accidente, atribuyendo al pozo de San L‚îú√≠zaro conexiones con otras dimensiones. Al fondo, el Pilar. Fuente: turiasona.blogspot.com/', 1981, 1981, 1981, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65769600, -0.87471300, '0101000020E6100000815A0C1EA6FDEBBFE25AED612FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31600384503.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31600384503.webp', 'https://www.flickr.com/photos/zaragozaantigua/31600384503/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25565, 'Puente de Piedra 2010', 'Foto: Oliver Duch. 6 de octubre de 2010. Actuaci‚îú‚îÇn musical del saxofonista Carlos Calvo y el tubista Javier Garc‚îú¬°a, aprovechando la reverberaci‚îú‚îÇn del arco norte del puente de Piedra. Tambi‚îú¬Æn cant‚îú‚îÇ Juncal Pibernat, en el marco de las fiestas del Arrabal. Los int‚îú¬Ærpretes llegaron en barcaza. Al fondo, el puente de Hierro. Fuente: Heraldo de Arag‚îú‚îÇn.', 2010, 2010, 2010, 'Siglo XXI', 'CASCO HIST‚îú√¥RICO', 41.65790400, -0.87498100, '0101000020E610000050E27327D8FFEBBF2CF4C13236D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32910873544.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32910873544.webp', 'https://www.flickr.com/photos/zaragozaantigua/32910873544/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23776, 'Torre Clavero 1994', 'Aspecto de la Torre Clavero, en el barrio rural de Movera. Se trataba de una edificaci‚îú‚îÇn rural mud‚îú¬Æjar del siglo XV, derribada en abril de 2009. Fuente: Colecci‚îú‚îÇn particular.', 1994, 1994, 1994, 'Anos 90', NULL, 41.66192500, -0.83605900, '0101000020E6100000CBD8D0CDFEC0EABFD0B359F5B9D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32928573651.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32928573651.webp', 'https://www.flickr.com/photos/zaragozaantigua/32928573651/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25568, 'R‚îú¬°o Ebro c.1986', 'Vista capturada en altura desde la torre de San Francisco de Borja del templo del Pilar con un interesante panorama ribere‚îú‚ñío de la ‚îú¬Æpoca. En el centro, el medieval puente de Piedra soportando intensa la circulaci‚îú‚îÇn rodada sobre un r‚îú¬°o Ebro chocolateado por la carga de materiales sedimentarios en ‚îú¬Æpoca de crecida. Tras ‚îú¬Æl, el moderno puente del Pilar o de Hierro. A la izquierda y entre ambos puentes, parte del antiguo barrio del Arrabal vertebrado en torno a la calle de Jes‚îú‚ïës. A la derecha e inmediato, el Club N‚îú√≠utico. Pocos a‚îú‚ñíos despu‚îú¬Æs, estos puentes ser‚îú¬°an objeto de sendas intervenciones, y al fondo se les a‚îú‚ñíadir‚îú¬°a el nuevo puente de la Uni‚îú‚îÇn para dar continuidad al segundo cintur‚îú‚îÇn de ronda. Fuente visual: foto giuseppedibari, en www.flickr.com', 1986, 1986, 1986, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65734300, -0.87523600, '0101000020E6100000F70489EDEE01ECBF94A0BFD023D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/42808018575.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/42808018575.webp', 'https://www.flickr.com/photos/zaragozaantigua/42808018575/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (25574, 'Puente de Piedra c.1934', 'El puente de Piedra en una imagen capturada desde la margen derecha con una vista que hacia el fondo alcanza hasta el Arrabal, donde despuntan los remates de las torrecillas de la iglesia de N‚î¨¬¨. S‚î¨¬¨. de Altab‚îú√≠s. Sobre el puente, fluida circulaci‚îú‚îÇn peatonal y un tranv‚îú¬°a haciendo su ruta hacia la margen izquierda (bien de la l‚îú¬°nea 4. Arrabal o de la l‚îú¬°nea 9. G‚îú√≠llego). El canicular nivel del r‚îú¬°o Ebro deja al descubierto el empedrado de siller‚îú¬°a que protege el basamento de las pilas del puente, y sobre ellas puede verse alg‚îú‚ïën pescador y unos pardales que hasta all‚îú¬° han llegado caminando. El fot‚îú‚îÇgrafo titul‚îú‚îÇ esta imagen de forma un tanto exagerada "Stone bridge piers" (muelles del puente de piedra).', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65694600, -0.87581600, '0101000020E61000007D08AA46AF06ECBF779E78CE16D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/51756392091.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/51756392091.webp', 'https://www.flickr.com/photos/zaragozaantigua/51756392091/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (26020, 'Arrabal 1938', 'A‚îú¬Ærea vista que recoge un buen sector del Arrabal, desde el Ebro y el puente de Piedra, pasando por el cuartel de San L‚îú√≠zaro, el convento de las franciscanas junto a la iglesia de Altab‚îú√≠s, la estaci‚îú‚îÇn del Norte, el arranque de la carretera de Catalu‚îú‚ñía, y la azucarera del Rabal. La imagen ha sido capturada desde el vuelo de un Junkers Ju-52 (T-2), alem‚îú√≠n aparato utilizado como bombardero diurno por la Legi‚îú‚îÇn C‚îú‚îÇndor desde su base de operaciones militares del Aer‚îú‚îÇdromo Sanjurjo (Garrapinillos), en apoyo a los nacionalistas durante la guerra de 1936-1939. Fuente visual: www.todocoleccion.net/', 1938, 1938, 1938, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65744900, -0.87514100, '0101000020E61000008670CCB22701ECBFDAE4F04927D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25668129935.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25668129935.webp', 'https://www.flickr.com/photos/zaragozaantigua/25668129935/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20917, 'Felipe II c.1585', '"Felipe II ante el retrato y las hijas del Duque de Villahermosa, D. Mart‚îú¬°n de Gurrea y Arag‚îú‚îÇn, en el convento de Santo Domingo, en Zaragoza", ‚îú‚îÇleo de Enrique M‚îú¬Ælida, ca. 1880.', 1585, 1585, 1585, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65798500, -0.88849900, '0101000020E610000025EB7074956EECBF18213CDA38D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19221236550.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19221236550.webp', 'https://www.flickr.com/photos/zaragozaantigua/19221236550/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20923, 'Almac‚îú¬Æn de la Sal 1760', 'Corte interior y exterior del arfol‚îú¬° (sic) principal de Zaragoza. Francisco de Velasco y Juli‚îú√≠n de Yarza, 1760. Alzado del nuevo edificio del alfol‚îú¬° o almac‚îú¬Æn de la Sal de Zaragoza, construido en el solar del anterior, en el camino de la Ribera y con traseras a la calle Bonaire (luego Ab‚îú¬Æn Aire), que permaneci‚îú‚îÇ en pie hasta el ‚îú‚ïëltimo tercio del siglo XX en su ubicaci‚îú‚îÇn del paseo de Echegaray y Caballero 29, luego 86-88, actual 84. El acceso del mineral, procedente de Remolinos y otras canteras, se realizaba mediante barcas a trav‚îú¬Æs de una mina o t‚îú‚ïënel desde el r‚îú¬°o Ebro hasta el alfol‚îú¬°, a la altura del hueco de la izquierda del edificio, bajo las escaleras. Fuente: Archivo General de Simancas. Ministerio de Cultura de Espa‚îú‚ñía.', 1760, 1760, 1760, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20479807868.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20479807868.webp', 'https://www.flickr.com/photos/zaragozaantigua/20479807868/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20981, 'Palacio de la Inquisici‚îú‚îÇn 1820', '"The Holy Office of Zaragoza being plundered by the people in March 1820", grabado que representar‚îú¬°a el saqueo de la sede de la Inquisici‚îú‚îÇn de Zaragoza, situado en el palacio de Villahermosa de la calle de Predicadores entre 1760 y 1820. La imagen mostrar‚îú¬°a las traseras del edificio en la ribera del Ebro, con el puente de piedra al fondo. 1820 fue la fecha en que se aboli‚îú‚îÇ la Inquisici‚îú‚îÇn en Espa‚îú‚ñía por tercera vez, hasta que lo fue definitivamente en 1834. Fuente: www.akg-images.co.uk/', 1820, 1820, 1820, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65812400, -0.88523600, '0101000020E610000049BDA772DA53ECBF3A5B40683DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20883737561.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20883737561.webp', 'https://www.flickr.com/photos/zaragozaantigua/20883737561/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (20999, 'Calle de Predicadores c.1855', 'Dibujo de Valent‚îú¬°n Carderera centrado en la monumental escalera de acceso al piso superior de la que fuera casa de los duques de Villahermosa en la antigua calle de Predicadores, habilitada en 1842 como c‚îú√≠rceles p‚îú‚ïëblicas. Este singular espacio interior desapareci‚îú‚îÇ luego por derribo. Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garc‚îú¬°a Guatas, Los ‚îú√≠lbumes de Pedrola. Apuntes y acuarelas de Valent‚îú¬°n Carderera en los ‚îú√≠lbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1855, 1855, 1855, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65757300, -0.88504100, '0101000020E6100000F6CFD3804152ECBFC6DD205A2BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40075399274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40075399274.webp', 'https://www.flickr.com/photos/zaragozaantigua/40075399274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21125, 'Calle de la Democracia c.1889', 'Imagen centrada en el rotundo ingreso principal a la antigua casa de los duques de Villahermosa desde la calle de la Democracia. La placa sobre la puerta informa de la funci‚îú‚îÇn efectiva dada a este emblem‚îú√≠tico lugar desde 1842: c‚îú√≠rceles p‚îú‚ïëblicas o nacionales. Al fondo, el patio que daba acceso a las dependencias carcelarias, con notable y animado trasiego de visitas. Esta gran casa del siglo XVI, remodelada en el XVII, ejerci‚îú‚îÇ en el siglo de Las Luces funciones militares (cuartel de caballer‚îú¬°a), y luego soport‚îú‚îÇ la sede del Tribunal de la Inquisici‚îú‚îÇn. Desde 1821 era de propiedad municipal, cedida por el Estado para c‚îú√≠rceles nacionales y juzgados. Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garc‚îú¬°a Guatas, Los ‚îú√≠lbumes de Pedrola. Apuntes y acuarelas de Valent‚îú¬°n Carderera en los ‚îú√≠lbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65757300, -0.88504100, '0101000020E6100000F6CFD3804152ECBFC6DD205A2BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/39981705274.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/39981705274.webp', 'https://www.flickr.com/photos/zaragozaantigua/39981705274/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21128, 'C‚îú√≠rceles p‚îú‚ïëblicas c.1889', 'Luminosa imagen del patio interior principal de la antigua casa de los duques de Villahermosa en el n‚î¨‚ïë 64 de la calle de la Democracia, habilitada como c‚îú√≠rceles p‚îú‚ïëblicas o nacionales. Hacia la izquierda, cercano al paseo del Ebro, se acced‚îú¬°a a un patio secundario que se convert‚îú¬°a en el escenario donde se instalaba el pat‚îú¬°bulo para ejecuci‚îú‚îÇn de los reos a pena de muerte. Fuente visual: Archivo Palacio Villahermosa (Pedrola), en Manuel Garc‚îú¬°a Guatas, Los ‚îú√≠lbumes de Pedrola. Apuntes y acuarelas de Valent‚îú¬°n Carderera en los ‚îú√≠lbumes del palacio de los Duques de Villahermosa de Pedrola, IFC, 2017.', 1889, 1889, 1889, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65782900, -0.88498800, '0101000020E61000004147AB5AD251ECBF21AE9CBD33D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40734376231.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40734376231.webp', 'https://www.flickr.com/photos/zaragozaantigua/40734376231/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21279, 'Vista San Pablo c.1905', 'Postal de la Fototipia "Madriguera" (Barcelona), de la serie "Zaragoza", con el n‚îú‚ïëmero 48, titulada "Vista panor‚îú√≠mica del Ebro". Vista del barrio de San Pablo desde la torre de su iglesia. Destaca en el centro la Casa de Amparo, en construcci‚îú‚îÇn. Al fondo, puente del Ferrocarril sobre el r‚îú¬°o Ebro. Fuente: www.ebay.es', 1905, 1905, 1905, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.65781900, -0.88796600, '0101000020E6100000CCB73EAC376AECBFFED7B96933D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24573555199.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24573555199.webp', 'https://www.flickr.com/photos/zaragozaantigua/24573555199/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21281, 'Puente del ferrocarril 1900', 'Postal "Zaragoza. Puente del ferrocarril sobre el Ebro", editada y publicada por la fototipia de Lucas Escol‚îú√≠ para la Uni‚îú‚îÇn Postal Universal. En la imagen, el puente del ferrocarril de 1870, recrecido en 1879, capturado desde la orilla derecha del r‚îú¬°o, inmediata al desag‚îú‚ïùe de la acequia de la Almozara, donde los Viveros del Ayuntamiento. Al otro lado, la margen izquierda, con la peque‚îú‚ñía arboleda de la Hortilla y el desemboque de la acequia del mismo nombre.', 1900, 1900, 1900, 'Anos 1900', 'CASCO HIST‚îú√¥RICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24733190025.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24733190025.webp', 'https://www.flickr.com/photos/zaragozaantigua/24733190025/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21486, 'P.‚î¨‚ïë del Ebro 1926', 'Imagen capturada junto al n‚îú‚ïëmero 29 del terroso paseo del Ebro, donde perduraba el ilustrado y dieciochesco edificio del antiguo Almac‚îú¬Æn o P‚îú‚îÇsito de la Sal de la ciudad, en desuso de esas funciones desde hac‚îú¬°a tiempo. En el momento de realizar esta fotograf‚îú¬°a Lucien Roisin, en su puerta figuraba la inscripci‚îú‚îÇn "Almac‚îú¬Æn de cereales Pardina". Fuente visual: Zaragoza a‚îú‚ñíos veinte. 81 fotograf‚îú¬°as de Roisin (1925-1931), IFC.', 1926, 1926, 1926, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15020930688.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15020930688.webp', 'https://www.flickr.com/photos/zaragozaantigua/15020930688/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21496, 'Casa Consistorial. A‚îú‚ñíos 20', 'El Convento de Santo Domingo de la Orden de Predicadores de Zaragoza fue fundado por Jaime I. El Refectorio fue construido en el s. XIV y su importancia era tal que las Cortes del Reino se reunieron varias veces en ‚îú¬Æl (ss. XIV-XV). La iglesia conventual fue reedificada en el XVII a la forma barroca, enorme, la tercera en tama‚îú‚ñío tras El Pilar y La Seo. Las leyes desamortizadoras vaciaron el Convento, que pas‚îú‚îÇ a manos municipales. El templo fue demolido para ensanchar la calle de la Democracia, y para instalar el Asilo Municipal. Otras dependencias fueron convertidas en almacenes. En 1888 se instala un Colegio Preparatorio Militar (uno de los cuatro de todo el Estado), y se piquetea todo menos el Refectorio, que se inserta dentro del nuevo edificio, ideado por Ricardo Magdalena. Inaugurado en 1890, este colegio militar estuvo funcional hasta 1892. Luego fue Museo de Bellas Artes, y desde 1912, Casa Consistorial, hasta 1965. En la imagen, puerta principal, situada en la calle de la Democracia, con buenas vistas a la plaza de Santo Domingo, desde donde se ha hecho la foto.', 1920, 1920, 1929, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65800400, -0.88891600, '0101000020E610000030849CF7FF71ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15341739245.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15341739245.webp', 'https://www.flickr.com/photos/zaragozaantigua/15341739245/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21499, 'Arboleda de Macanaz 1923', 'AHPZ. Archivo fotogr‚îú√≠fico Julio Requejo. 12/12/1923. "En la arboleda." Imagen de la arboleda de Macanaz, con vista al fondo de "Manufacturas de lanas de Mor‚îú‚îÇn y An‚îú‚îÇs", factor‚îú¬°a dise‚îú‚ñíada por Miguel ‚îú√ºngel Navarro. Los paseantes de la arboleda, en d‚îú¬°a de ciercera, tienen al r‚îú¬°o a sus espaldas, y se dirigen al Camino de Ranillas, en un entorno que un par de a‚îú‚ñíos despu‚îú¬Æs (1925) ser‚îú√≠ ocupado por el Centro Nataci‚îú‚îÇn Helios. De todo el conjunto fabril, supervive la que durante muchos a‚îú‚ñíos fue "La Chimenea".', 1923, 1923, 1923, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.66024000, -0.88416300, '0101000020E6100000F8A92A34104BECBF6AC18BBE82D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15402888782.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15402888782.webp', 'https://www.flickr.com/photos/zaragozaantigua/15402888782/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21532, 'Pat‚îú¬°bulo 1922', 'Dibujo de D‚îú¬°az Dom‚îú¬°nguez, 1922. Aunque las ejecuciones zaragozanas se hab‚îú¬°an hecho tradicionalmente en el pellerich de la plaza del Mercado, en el siglo XIX se decidi‚îú‚îÇ separar el lugar de comercio de viandas y el de matac‚îú¬°a de humanos, trasladando el pat‚îú¬°bulo a las traseras de la c‚îú√≠rcel de Predicadores, en el paseo del Ebro. Los reos eran conducidos por la calle de la Triper‚îú¬°a, atravesaban el Arco de San Ildefonso y sub‚îú¬°an al entarimado de la imagen. En este lugar tambi‚îú¬Æn se hab‚îú¬°an producido fusilamientos masivos a principios del siglo XIX. Fuente: La Cadiera 114, 1957.', 1922, 1922, 1922, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65812400, -0.88523600, '0101000020E610000049BDA772DA53ECBF3A5B40683DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19436568684.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19436568684.webp', 'https://www.flickr.com/photos/zaragozaantigua/19436568684/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23167, 'Basilio Para‚îú¬°so 2009', 'Foto: Toni Gal‚îú√≠n. Inauguraci‚îú‚îÇn del busto de Basilio Para‚îú¬°so (empresario y pol‚îú¬°tico regeneracionsta aragon‚îú¬Æs, 1849-1930), obra de Florencio de Pedro, el 22 de enero de 2009. Se situ‚îú‚îÇ junto a la entrada de la C‚îú√≠mara de Comercio e Industria de Zaragoza, en el paseo de Isabel la Cat‚îú‚îÇlica 2, siendo trasladado a la reformada plaza de Basilio Para‚îú¬°so en diciembre de 2012. En la foto, familiares del homenajeado posan con Juan Alberto Belloch, alcalde de Zaragoza; Marcelino Iglesias, presidente del gobierno de Arag‚îú‚îÇn; y Manuel Teruel, presidente de la C‚îú√≠mara de Comercio. A estos ‚îú‚ïëltimos se les distingue porque no llevan abrigo. Fuente: Heraldo de Arag‚îú‚îÇn.', 2009, 2009, 2009, 'Siglo XXI', 'UNIVERSIDAD', 41.63732400, -0.89877800, '0101000020E61000003FA88B14CAC2ECBF5B7A34D593D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32916311906.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32916311906.webp', 'https://www.flickr.com/photos/zaragozaantigua/32916311906/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21581, 'Chalet Helios 1925', 'Imagen del original "chalet" que form‚îú‚îÇ parte de las primeras y precarias instalaciones de la "Sociedad Naturista Helios". Durante la sobresaliente riada del Ebro de 1930, este chalet asemejaba m‚îú√≠s un lacustre palafito, rodeado de agua. Con el tiempo, ir‚îú¬°an tomando forma otras instalaciones naturistas: un gimnasio, un campo de tennis, otro de juego de pelota, duchas, columpios, y un estanque. En la imagen, y tras el edificio, y la natural valla, el camino de acceso que proven‚îú¬°a, por la derecha, de la arboleda de Macanaz. A su derecha, e inmediato, se levantar‚îú√≠ m‚îú√≠s tarde un pabell‚îú‚îÇn para vestuarios, y el tabl‚îú‚îÇn que desciende de su puerta de acceso ser‚îú√≠ sustituido por unas escaleras m‚îú√≠s consistentes que desembocaban en una cancha de basket. M‚îú√≠s tarde, tras una de las sucesivas ampliaciones del ya redenominado y exitoso "Centro Nataci‚îú‚îÇn Helios", este chalet se convirti‚îú‚îÇ en resto arqueol‚îú‚îÇgico.', 1925, 1925, 1925, 'Anos 20', 'CASCO HIST‚îú√¥RICO', 41.65996200, -0.88450500, '0101000020E610000059C0046EDD4DECBF274D83A279D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/24400351970.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/24400351970.webp', 'https://www.flickr.com/photos/zaragozaantigua/24400351970/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21667, 'Plaza de Santo Domingo 1930', '"El Ayuntamiento" (Plaza de Santo Domingo).', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65797200, -0.88904500, '0101000020E6100000A583F57F0E73ECBF84D72E6D38D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14688633890.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14688633890.webp', 'https://www.flickr.com/photos/zaragozaantigua/14688633890/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21681, 'Puente del ferrocarril 1936', 'AHPZ-Archivo Coyne, Manuel Coyne, 1936. Puente del ferrocarril sobre el r‚îú¬°o Ebro.', 1936, 1936, 1936, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.66145000, -0.89009600, '0101000020E6100000029D499BAA7BECBF38F8C264AAD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14877669251.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14877669251.webp', 'https://www.flickr.com/photos/zaragozaantigua/14877669251/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21684, 'Santa Luc‚îú¬°a 1930', '"Iglesia de Santa Luc‚îú¬°a".', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14895193433.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14895193433.webp', 'https://www.flickr.com/photos/zaragozaantigua/14895193433/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21688, 'Cincomarzada 1930', 'Vecinos del barrio de San Pablo celebran la Cincomarzada en la arboleda de Macanaz, con el fondo de las instalaciones de la f‚îú√≠brica de Manufacturas de lanas de Mor‚îú‚îÇn y An‚îú‚îÇs".', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65954300, -0.89020900, '0101000020E61000000C5BB395977CECBF22A7AFE76BD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15000345448.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15000345448.webp', 'https://www.flickr.com/photos/zaragozaantigua/15000345448/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21756, 'Callej‚îú‚îÇn del Arpa 1934', 'Imagen del callej‚îú‚îÇn denominado "Arpa" y, al fondo, la antigua posada de San Jer‚îú‚îÇnimo. Esta posada, sita en un caser‚îú‚îÇn rodeado de viviendas recayentes a la calle Bonaire (luego, Aben-Aire) por el norte, y Predicadores (luego, Democracia), por el sur, ten‚îú¬°a en este "sombr‚îú¬°o" callej‚îú‚îÇn su entrada y salida desde la calle Predicadores-Democracia. Desde antiguo, las calles del entorno de la plaza del Mercado estaban bien surtidas de mesones (luego, posadas) como este, desde la ribera del Ebro, y hasta la calle Doncellas, junto al convento de San Ildefonso. Esta zona de la imagen, adem‚îú√≠s, form‚îú‚îÇ parte del "Burdel Viejo" de la ciudad. Fuente visual: A. de la Barrera, revista "Estampa" (Madrid).', 1934, 1934, 1934, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65724100, -0.88315500, '0101000020E61000006D904946CE42ECBF904B1C7920D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22567758507.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22567758507.webp', 'https://www.flickr.com/photos/zaragozaantigua/22567758507/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21770, 'R‚îú¬°o Ebro c.1930', 'Postal editada por la Uni‚îú‚îÇn Postal Universal con imagen de las barcazas que cruzaban el Ebro en el tramo entre el puente de Piedra y la "Caseta de Ba‚îú‚ñíos", a trav‚îú¬Æs de tres embarcaderos. Esta navegaci‚îú‚îÇn ten‚îú¬°a car‚îú√≠cter funcional (conectar ambas riberas), y recreativo (acceso r‚îú√≠pido a la arboleda de Macanaz). Fuente visual: www.delcampe.net/', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65896600, -0.88306900, '0101000020E6100000C99063EB1942ECBF859675FF58D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22829128757.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22829128757.webp', 'https://www.flickr.com/photos/zaragozaantigua/22829128757/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21786, 'Calle de los Infantes c.1930', 'Imagen de la original calle de los Infantes de San Pablo, con entrada por la calle de Aben-Aire, y sin salida. Paralela a las calles de Predicadores, al sur, y a la m‚îú√≠s peque‚îú‚ñía de Constantino, al norte. Los edificios son construcciones seriadas levantadas en el siglo XVIII, de alquiler. La imagen ha sido realizada casi al comienzo de la calle, mirando hacia el lado de los pares. A mediados de los a‚îú‚ñíos 70 del pasado siglo, toda esta zona padeci‚îú‚îÇ una intervenci‚îú‚îÇn radical, incluyendo la demolici‚îú‚îÇn de todo lo que aparece en imagen. Sic transit gloria urbis. Fuente visual: AMZ.', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65762100, -0.88373300, '0101000020E6100000C5ABAC6D8A47ECBFD714C8EC2CD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/23247884096.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/23247884096.webp', 'https://www.flickr.com/photos/zaragozaantigua/23247884096/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21823, 'Embarcadero Ebro c.1930', 'Imagen capturada desde las inmediaciones de la p‚îú‚ïëblica Caseta de los Ba‚îú‚ñíos de la margen izquierda, junto a la Sociedad Naturista "Helios", del m‚îú√≠s occidental de los tres embarcaderos habilitados para acceso a la zona recreativa de la arboleda de Macanaz. La a‚îú¬Ærea sirga conectaba con uno de los dos embarcaderos de la margen derecha, en el paseo del Ebro, escalonados cerca del acceso a la calle de Antonio P‚îú¬Ærez. Fuente visual: Arxiu Nacional de Catalunya', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65896600, -0.88306900, '0101000020E6100000C99063EB1942ECBF859675FF58D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32050239495.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32050239495.webp', 'https://www.flickr.com/photos/zaragozaantigua/32050239495/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21098, 'Puente de Piedra c.1881', 'Fondo Documental Hist‚îú‚îÇrico de las Cortes de Arag‚îú‚îÇn. (ca. 1880). Puente de Piedra de Zaragoza.', 1881, 1881, 1881, 'Siglo XIX', 'CASCO HIST‚îú√¥RICO', 41.65704200, -0.87541900, '0101000020E61000003881E9B46E03ECBF990CC7F319D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14874431941.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14874431941.webp', 'https://www.flickr.com/photos/zaragozaantigua/14874431941/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21826, 'Postigo del Ebro 1930', 'Imagen del antiguo desemboque, en descenso, de la calle del Postigo del Ebro en el paseo del Ebro. Al fondo, el arranque de esta calle desde la de la Democracia, antigua de Predicadores, que tras el 18 de julio de 1936 recuper‚îú‚îÇ esa denominaci‚îú‚îÇn. El nombre de Postigo del Ebro es un recuerdo del antiguo "postigo", o paso, que por esta calle abr‚îú¬°a el antiguo barrio de la Poblaci‚îú‚îÇn del Rey, o de San Pablo, hacia la ribera del r‚îú¬°o. La caseta de madera de la izquierda es una rememoranza de cuando el tr‚îú√≠nsito por estos pasos estaba vigilado. Como indica el cartel, a Barcelona se va por la izquierda (seg‚îú‚ïën se mire). Fuente visual: Miguel Mar‚îú¬°n Chivite, peri‚îú‚îÇdico "Heraldo de Arag‚îú‚îÇn".', 1930, 1930, 1930, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65820600, -0.88621100, '0101000020E6100000E55FCB2BD75BECBFF7031E1840D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32541554445.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32541554445.webp', 'https://www.flickr.com/photos/zaragozaantigua/32541554445/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21837, 'Convento de Santa Luc‚îú¬°a c.1935', 'Imagen centrada en el interior del exclusivo y poligonal ‚îú√≠bside de cinco lados de la iglesia del antiguo convento cisterciense de Santa Luc‚îú¬°a, una irrepetible muestra del g‚îú‚îÇtico-mud‚îú¬Æjar desaparecido durante la prodigiosa d‚îú¬Æcada de los a‚îú‚ñíos sesenta del pasado siglo. Esta iglesia conventual estaba ubicada entre la calle de Santa Luc‚îú¬°a, y la plaza de Santo Domingo, y luc‚îú¬°a estas enrevesadas trazas desde que fueron compuestas posiblemente a finales del siglo XVI. Como en otros casos, estaba incluida en el cat‚îú√≠logo del mud‚îú¬Æjar local m‚îú√≠s selecto, hasta que fue vendida y derribada. Fuente visual: Francisco Abbad R‚îú¬°os. "Gu‚îú¬°as art‚îú¬°sticas de Espa‚îú‚ñía. Zaragoza" (1952).', 1935, 1935, 1935, 'Anos 30', 'CASCO HIST‚îú√¥RICO', 41.65804100, -0.88976500, '0101000020E61000009B030473F478ECBFAC36FFAF3AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34733019320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34733019320.webp', 'https://www.flickr.com/photos/zaragozaantigua/34733019320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (21954, 'Puente del Ferrocarril 1946', 'Desde la alameda de Macanaz, cerca de la confluencia de la antigua acequia de la Ortilla en el r‚îú¬°o Ebro, imagen del Puente del Ferrocarril. Inaugurado en 1870, fue recrecido en altura en 1879 tras comprobar que las riadas de este r‚îú¬°o, cuando vienen, no son cualesquiera cosa. La imagen muestra que ese recrecimiento fue muy necesario. A nuestras espaldas queda el Centro Nataci‚îú‚îÇn Helios, que se hab‚îú¬°a cambiado de nombre hac‚îú¬°a poco (hasta 1942 fue "Centro Naturista Helios"). Al otro lado del r‚îú¬°o, tras el puente, construcciones en torno al antiguo Camino de la Almozara, las calles Padre Landa y Juan Sari‚îú‚ñíena. La presencia de la gigante "Qu‚îú¬°mica", a la izquierda, fuera de plano, determinaba una barriada esencialmente industriosa, m‚îú√≠s all‚îú√≠ de donde estuviera la Puerta y el Molino de Sancho. A la derecha, el denso Soto de la Almozara. Al a‚îú‚ñío siguiente de esta imagen, el Puente del Ferrocarril ser‚îú√≠ modificado para a‚îú‚ñíadirle un segundo tablero reforzado que permitir‚îú√≠ la doble direcci‚îú‚îÇn a unas locomotoras de vapor m‚îú√≠s potentes y pesadas. Este puente seguir‚îú√≠ prestando servicio ferroviario hasta 1976, cuando tras el desmantelamiento de la l‚îú¬°nea de enlace, sea reformado para tr‚îú√≠fico viario a motor de explosi‚îú‚îÇn. En la imagen, un convoy arrastrado por una "vaporosa", se encamina traqueteando hacia la veterana Estaci‚îú‚îÇn del Norte. Fuente visual: fotograf‚îú¬°a de Mariano Lacruz Berdejo, amablemente aportada por Mariano Lacruz P‚îú¬Ærez (Archivo Familia Lacruz P‚îú¬Ærez).', 1946, 1946, 1946, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.66154300, -0.88990800, '0101000020E61000004F5C8E57207AECBFE9F2E670ADD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19457423573.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19457423573.webp', 'https://www.flickr.com/photos/zaragozaantigua/19457423573/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22010, 'Torre de San Pablo c.1945', '"R‚îú¬°o", pintura de Jes‚îú‚ïës Fern‚îú√≠ndez Barrio, a‚îú‚ñíos 40. Vista de la torre de San Pablo desde la margen izquierda del r‚îú¬°o Ebro. Fuente: fernandezbarrio.es', 1945, 1945, 1945, 'Anos 40', 'CASCO HIST‚îú√¥RICO', 41.65901700, -0.88521400, '0101000020E610000054C37E4FAC53ECBF074147AB5AD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/40737002754.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/40737002754.webp', 'https://www.flickr.com/photos/zaragozaantigua/40737002754/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22043, 'Municipales motorizados 1955', 'Ayuntamiento de Zaragoza/Mar‚îú¬°n Chivite. 17 de septiembre de 1955. La Secci‚îú‚îÇn Motorista de la Polic‚îú¬°a Municipal es presentada en sociedad en la Plaza de Santo Domingo, junto al Ayuntamiento. De fondo, a la derecha, el edificio del Mercado de Pescados, construido en 1928. A la izquierda, acceso a la calle de las Armas.', 1955, 1955, 1955, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65738600, -0.88899600, '0101000020E61000004BCB48BDA772ECBF946C753925D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14758346159.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14758346159.webp', 'https://www.flickr.com/photos/zaragozaantigua/14758346159/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22055, 'Fernando Rey 1951', 'Ayuntamiento de Zaragoza/Mar‚îú¬°n Chivite. 6 de mayo de 1951. Acto de imposici‚îú‚îÇn de la medalla de plata de Zaragoza al actor Fernando Rey por su interpretaci‚îú‚îÇn de Palafox en la pel‚îú¬°cula "Agustina de Arag‚îú‚îÇn". Aurora Bautista, que hac‚îú¬°a de Agustina, atenta a la imposici‚îú‚îÇn. Impone Jos‚îú¬Æ Mar‚îú¬°a Garc‚îú¬°a Belenguer, alcalde de la ciudad entre 1949 y 1954.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65798800, -0.88890000, '0101000020E6100000C442AD69DE71ECBF8A9466F338D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14916457916.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14916457916.webp', 'https://www.flickr.com/photos/zaragozaantigua/14916457916/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22056, 'Aurora Bautista 1951', 'Ayuntamiento de Zaragoza/Mar‚îú¬°n Chivite. 6 de mayo de 1951. Acto de imposici‚îú‚îÇn de la medalla de plata de Zaragoza a la actriz Aurora Bautista. Fue concedida por la corporaci‚îú‚îÇn por su interpretaci‚îú‚îÇn del papel de Agustina Zaragoza en la pel‚îú¬°cula "Agustina de Arag‚îú‚îÇn". Impone Jos‚îú¬Æ Mar‚îú¬°a Garc‚îú¬°a Belenguer, alcalde de la ciudad entre 1949 y 1954.', 1951, 1951, 1951, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65800400, -0.88891600, '0101000020E610000030849CF7FF71ECBF8F519E7939D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14916507946.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14916507946.webp', 'https://www.flickr.com/photos/zaragozaantigua/14916507946/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22144, 'Convento de Santa Luc‚îú¬°a c.1950', 'Imagen de los huertos interiores del antiguo convento de Santa Luc‚îú¬°a, en la calle de los Predicadores. A la izquierda, la nave de la iglesia conventual g‚îú‚îÇtico-mud‚îú¬Æjar, modificada en el siglo XVI, y la espada‚îú‚ñía de su demediada torre. Tras ella, una peque‚îú‚ñía chimenea de la Azucarera Agr‚îú¬°cola del Pilar, antigua alcoholera. Los edificios del centro son recayentes a la plaza de Santo Domingo, y al edificio del Ayuntamiento, que sobresale al fondo. Este conjunto conventual fue vendido y derribado a finales de la prodigiosa d‚îú¬Æcada de los a‚îú‚ñíos 60 del pasado siglo, ad maiorem dei gloriam. En su lugar se construyeron interesantes moles edilicias que dignifican el patrimonio urbano hasta extremos irreproducibles. La poca calidad de la in‚îú¬Ædita imagen refuerza el sentido on‚îú¬°rico, irreal, de una antigua zona cuya mutaci‚îú‚îÇn ha sido, cuando menos, antol‚îú‚îÇgica. Fuente visual: "La arquitectura aragonesa del siglo XVI", Javier Ib‚îú√≠‚îú‚ñíez Fern‚îú√≠ndez, IFC.', 1950, 1950, 1950, 'Anos 50', 'CASCO HIST‚îú√¥RICO', 41.65794000, -0.88964500, '0101000020E6100000F29881CAF877ECBF795DBF6037D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/25692240204.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/25692240204.webp', 'https://www.flickr.com/photos/zaragozaantigua/25692240204/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (23969, 'Pabell‚îú‚îÇn Franc‚îú¬Æs 1966', 'Archivo Municipal. Gerardo Sancho Ramo. Junio 1966. Imagen del "Primer Congreso Diocesano de hombres cat‚îú‚îÇlicos" en el Pabell‚îú‚îÇn Franc‚îú¬Æs de la Feria de Muestras, customizado para la ocasi‚îú‚îÇn.', 1966, 1966, 1966, 'Anos 60', 'UNIVERSIDAD', 41.63755100, -0.90001500, '0101000020E6100000221ADD41ECCCECBF1C446B459BD14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15097624994.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15097624994.webp', 'https://www.flickr.com/photos/zaragozaantigua/15097624994/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (24079, 'Parque Primo de Rivera 1967', 'Imagen capturada durante la inauguraci‚îú‚îÇn oficial del monumento al nicarag‚îú‚ïùense F‚îú¬Ælix Rub‚îú¬Æn Sarmiento (Rub‚îú¬Æn Dar‚îú¬°o) realizado en piedra y bronce por el escultor ‚îú√ºngel Orensanz y emplazado en la rosaleda del parque de Primo de Rivera con motivo del centenario del nacimiento de este poeta. Centran el posado el alcalde de Zaragoza, Ces‚îú√≠reo Alierta, y el embajador de Nicaragua, Vicente Urcuyo. Junto a ellos, embajadores de Colombia, Costa Rica, Honduras y Panam‚îú√≠, y representantes de diversas instancias diplom‚îú√≠ticas y culturales. Fuente visual: Jarke/Jaria, AMZ.', 1967, 1967, 1967, 'Anos 60', 'UNIVERSIDAD', 41.63287100, -0.89624200, '0101000020E6100000F8A6E9B303AEECBF1DCBBBEA01D14440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/38525505421.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/38525505421.webp', 'https://www.flickr.com/photos/zaragozaantigua/38525505421/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22489, 'Convento de Santo Domingo 1967', 'Imagen capturada en el interior del antiguo refectorio del convento de los frailes predicadores de Santo Domingo, cuando todav‚îú¬°a era utilizado como archivo-biblioteca municipal, tal y como ven‚îú¬°a siendo desde que la Casa Consistorial estuviera ubicada en las inmediatas dependencias de la Plaza de Santo Domingo, en el edificio de la antigua Academia Preparatoria Militar de Zaragoza. Este espacio g‚îú‚îÇtico-mud‚îú¬Æjar fue construido en los inicios del siglo XIV como refectorio (comedor) del gran convento de los predicadores, seg‚îú‚ïën factura llevada a cabo en piedra y ladrillo por los alarifes mud‚îú¬Æjares de la familia Bellito. Consta de una sala rectangular distribuida en dos naves divididas en cinco tramos, con columnas de piedra que soportan una b‚îú‚îÇveda de crucer‚îú¬°a. En el siglo XIX fue objeto de reformas por el arquitecto Ricardo Magdalena, como los grandes ‚îú‚îÇculos sobre los apuntados ventanales de la derecha (con orientaci‚îú‚îÇn sur), que originalmente adem‚îú√≠s se abr‚îú¬°an al claustro principal del convento, espacio central junto al cual tambi‚îú¬Æn estaba adosada la gran iglesia. El estucado y pintura que oculta los ladrillos de paredes y b‚îú‚îÇvedas era tambi‚îú¬Æn signo de las modas imperantes cuando aquella intervenci‚îú‚îÇn. Fuente visual: fotograf‚îú¬°a de Guillermo Fat‚îú√≠s Ojuel en Torralba, Federico; G‚îú‚îÇmez de Valenzuela, Manuel, Cat‚îú√≠logo de monumentos hist‚îú‚îÇricos-art‚îú¬°sticos y edificios de inter‚îú¬Æs para el estudio del arte en la ciudad de Zaragoza. Cuadernos de Arag‚îú‚îÇn n‚î¨‚ïë 73, IFC.', 1967, 1967, 1967, 'Anos 60', 'CASCO HIST‚îú√¥RICO', 41.65845500, -0.88865700, '0101000020E61000002E910BCEE06FECBF9F71E14048D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/44186002854.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/44186002854.webp', 'https://www.flickr.com/photos/zaragozaantigua/44186002854/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22584, 'Regatas Ebro 1970', 'Archivo Municipal. Gerardo Sancho Ramo. Setiembre 1970. Unas emotivas regatas deportivas sobre el Ebro pueden servir, tal es el caso, para capturar una muy interesante visual de los edificios de la margen derecha, o m‚îú√≠s bien de los restos de los edificios que una vez hubo, entre el colegio Valent‚îú¬°n Zabala (a la izquierda), y el antiguo palacio de los Duques de Villahermosa (s. XVII) utilizado luego como c‚îú√≠rcel, juzgados, y c‚îú√≠rcel de mujeres durante el franquismo. La emergencia de la torre de la iglesia de San Pablo, y de uno de los torreones del palacio aclaran bastante la perspectiva, aunque resulta absolutamente incomparable con la actualidad pues, salvo la torre y el torre‚îú‚îÇn, ning‚îú‚ïën elemento de este panorama supervive.', 1970, 1970, 1970, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65786700, -0.88343300, '0101000020E61000001FA166481545ECBF0F0F61FC34D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15612789918.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15612789918.webp', 'https://www.flickr.com/photos/zaragozaantigua/15612789918/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22657, 'Puente del ferrocarril 1978', 'El original Puente del Ferrocarril sobre el Ebro prest‚îú‚îÇ servicio, con modificaciones, ampliaciones y recrecimiento incluido, desde 1870 y hasta 1976. Luego ser‚îú√≠ reformado para el prioritario tr‚îú√≠fico viario a motor de explosi‚îú‚îÇn. En la imagen, el puente ya desmantelado de elementos ferroviarios, capturado desde la margen izquierda. Al fondo, la ciudad con el punto de encuentro del barrio de San Pablo, con el de la Qu‚îú¬°mica, o Almozara. En medio, sobresale el llamativo cartel de Piensos "Cia". Fuente visual: Archivo P‚îú‚ïëblico Municipal, Gerardo Sancho Ramo.', 1978, 1978, 1978, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.66209200, -0.88962400, '0101000020E6100000149337C0CC77ECBFBC783F6EBFD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/21845314095.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/21845314095.webp', 'https://www.flickr.com/photos/zaragozaantigua/21845314095/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22719, 'R‚îú¬°o Ebro 1979', 'Foto: Tom‚îú√≠s Mora. Imagen nocturna tomada desde la plaza de Santo Domingo, con el paseo de Echegaray y Caballero en primer t‚îú¬Ærmino y las instalaciones del Club Helios al otro lado del Ebro. Fuente: www.facebook.com/photo.php?fbid=1439169236111190&set=...', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65862600, -0.88838100, '0101000020E6100000A968ACFD9D6DECBFCC2555DB4DD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30138428323.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30138428323.webp', 'https://www.flickr.com/photos/zaragozaantigua/30138428323/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22729, 'Calle Predicadores 1979', 'Foto: Tom‚îú√≠s Mora Ruata. Imagen nocturna tomada desde la plaza de Santo Domingo, centrada en la calle Predicadores. Fuente: www.facebook.com/photo.php?fbid=1439814096046704&set=...', 1979, 1979, 1979, 'Anos 70', 'CASCO HIST‚îú√¥RICO', 41.65771200, -0.88733000, '0101000020E61000004C4F58E20165ECBFE71725E82FD44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30773955585.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30773955585.webp', 'https://www.flickr.com/photos/zaragozaantigua/30773955585/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
INSERT INTO public.photos VALUES (22884, 'Calle Predicadores 1987', 'En 1987 se derribaron las casas de los entonces n‚îú‚ïëmeros 20 al 30 de la calle de Predicadores de Zaragoza. La normativa vigente exig‚îú¬°a la realizaci‚îú‚îÇn de catas arqueol‚îú‚îÇgicas, que fueron solicitadas p‚îú‚ïëblicamente por Guillermo Fat‚îú√≠s y realizadas pese a las urgencias constructivas del Ayuntamiento presidido por Antonio Gonz‚îú√≠lez Trivi‚îú‚ñío. Un equipo dirigido por Mar‚îú¬°a Pilar Galve sac‚îú‚îÇ a la luz la romana Necr‚îú‚îÇpolis occidental de Caesaraugusta, del siglo III, adem‚îú√≠s de constatar que en la zona (periferia de la ciudad, m‚îú√≠s all‚îú√≠ de la Puerta de Toledo) se produjeron enterramientos musulmanes hasta el siglo X. El hallazgo m‚îú√≠s relevante fue un mausoleo, en el solar de los n‚îú‚ïëmeros 24-26, esquina derecha con la calle de Ab‚îú¬Æn Aire. Este peque‚îú‚ñío monumento, ‚îú‚ïënico en la ciudad, merec‚îú¬°a ser conservado en opini‚îú‚îÇn de los arque‚îú‚îÇlogos, pero no lo fue, siguiendo el criterio de los entonces responsables pol‚îú¬°ticos. En la foto, en primer plano, el mausoleo hoy destruido, n‚îú‚ïëcleo al que se fueron aglutinando las dem‚îú√≠s inhumaciones de la zona. Fuente: Mar‚îú¬°a Pilar Galve Izquierdo, La necr‚îú‚îÇpolis occidental de Caesaraugusta en el siglo III, 2008.', 1987, 1987, 1987, 'Anos 80', 'CASCO HIST‚îú√¥RICO', 41.65732100, -0.88355200, '0101000020E6100000B1170AD80E46ECBFADFC321823D44440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19759420659.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19759420659.webp', 'https://www.flickr.com/photos/zaragozaantigua/19759420659/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923');
